#[test]
fn resume_hydration_backfills_legacy_tool_name_from_call() {
    let mut app = test_app(SessionMode::Build);
    let result = sample_tool_result("shell", "ok");
    let mut legacy_result = serde_json::to_value(result).expect("serialize tool result");
    legacy_result
        .as_object_mut()
        .expect("tool result object")
        .remove("tool_name");

    hydrate_transcript_item(
        &mut app,
        squeezy_store::HydratedTranscriptItem::ToolResult {
            call: Some(squeezy_store::HydratedToolCall {
                call_id: "call-1".to_string(),
                tool: "shell".to_string(),
                arguments: serde_json::json!({"command": "pwd"}),
            }),
            result: legacy_result,
        },
    );

    assert!(
        app.transcript
            .iter()
            .filter_map(|entry| match &entry.kind {
                TranscriptEntryKind::Log(log) => Some(log.message.as_str()),
                _ => None,
            })
            .all(|message| !message.contains("malformed tool-result")),
        "legacy tool result should hydrate without a warning: {:?}",
        app.transcript
    );
    let entry = app.transcript.first().expect("hydrated tool card");
    let tool = match &entry.kind {
        TranscriptEntryKind::ToolResult(tool) => tool,
        other => panic!("expected hydrated tool result, got {other:?}"),
    };
    assert_eq!(tool.result.tool_name, "shell");
    assert_eq!(
        tool.call.as_ref().map(|call| call.name.as_str()),
        Some("shell")
    );
}

#[test]
fn resume_hydration_reconstructs_function_call_output_card() {
    // The shape Squeezy actually persists for a tool result is the
    // model-facing FunctionCallOutput resume item, NOT a serialized
    // ToolResult. Hydration must reconstruct a card from it instead of
    // dropping it (which left resumed sessions with no tool-result cards).
    let mut app = test_app(SessionMode::Build);
    let model_output = sample_tool_result("shell", "Cargo.toml\nsrc").model_output();
    let result = serde_json::json!({
        "type": "function_call_output",
        "call_id": "call-1",
        "output": model_output,
    });

    hydrate_transcript_item(
        &mut app,
        squeezy_store::HydratedTranscriptItem::ToolResult {
            call: Some(squeezy_store::HydratedToolCall {
                call_id: "call-1".to_string(),
                tool: "shell".to_string(),
                arguments: serde_json::json!({"command": "ls"}),
            }),
            result,
        },
    );

    assert!(
        app.transcript.iter().all(|entry| !matches!(
            &entry.kind,
            TranscriptEntryKind::Log(log) if log.message.contains("malformed tool-result")
        )),
        "function-call-output result should hydrate without a warning: {:?}",
        app.transcript
    );
    let entry = app.transcript.first().expect("hydrated tool card");
    let tool = match &entry.kind {
        TranscriptEntryKind::ToolResult(tool) => tool,
        other => panic!("expected hydrated tool result, got {other:?}"),
    };
    // status + content come back faithfully from model_output(); tool_name and
    // call_id from the paired call.
    assert_eq!(tool.result.tool_name, "shell");
    assert_eq!(tool.result.call_id, "call-1");
    assert_eq!(tool.result.status, ToolStatus::Success);
    assert_eq!(
        tool.result.content,
        serde_json::json!({ "output": "Cargo.toml\nsrc" })
    );
    assert_eq!(
        tool.call.as_ref().map(|call| call.name.as_str()),
        Some("shell")
    );
}

#[test]
fn resume_hydration_reconstructs_card_without_paired_call() {
    // A tool result whose ToolCall event is missing still has to render — the
    // store guards against a missing call_id, so call_id survives, but the
    // tool name is unknown. The card must show rather than drop, and a
    // non-Success status must round-trip.
    let mut app = test_app(SessionMode::Build);
    let mut denied = sample_tool_result("shell", "nope");
    denied.status = ToolStatus::Denied;
    let result = serde_json::json!({
        "type": "function_call_output",
        "call_id": "call-9",
        "output": denied.model_output(),
    });

    hydrate_transcript_item(
        &mut app,
        squeezy_store::HydratedTranscriptItem::ToolResult { call: None, result },
    );

    let entry = app
        .transcript
        .first()
        .expect("hydrated tool card even without a paired call");
    let tool = match &entry.kind {
        TranscriptEntryKind::ToolResult(tool) => tool,
        other => panic!("expected hydrated tool result, got {other:?}"),
    };
    assert_eq!(tool.result.status, ToolStatus::Denied);
    assert_eq!(tool.result.call_id, "call-9");
    assert!(tool.result.tool_name.is_empty());
    assert!(tool.call.is_none());
}

#[test]
fn resume_hydration_surfaces_non_model_output_body_instead_of_dropping() {
    // A legacy or corrupt tool result whose `output` is not the
    // model_output() JSON object must still render — surface the raw text
    // rather than drop the card.
    let mut app = test_app(SessionMode::Build);
    let result = serde_json::json!({
        "type": "function_call_output",
        "call_id": "call-7",
        "output": "plain text, not json",
    });

    hydrate_transcript_item(
        &mut app,
        squeezy_store::HydratedTranscriptItem::ToolResult {
            call: Some(squeezy_store::HydratedToolCall {
                call_id: "call-7".to_string(),
                tool: "shell".to_string(),
                arguments: serde_json::json!({}),
            }),
            result,
        },
    );

    let entry = app.transcript.first().expect("hydrated tool card");
    let tool = match &entry.kind {
        TranscriptEntryKind::ToolResult(tool) => tool,
        other => panic!("expected hydrated tool result, got {other:?}"),
    };
    assert_eq!(tool.result.status, ToolStatus::Success);
    assert_eq!(
        tool.result.content,
        serde_json::Value::String("plain text, not json".to_string())
    );
    assert_eq!(tool.result.call_id, "call-7");
}

#[test]
fn tool_rows_summarize_diff_glob_read_and_plan_outputs() {
    let mut app = test_app(SessionMode::Build);

    let mut diff = sample_tool_result("diff_context", "");
    diff.call_id = "diff-1".to_string();
    diff.content = serde_json::json!({
        "mode": "worktree",
        "summary": {"files_changed": 2, "additions": 3, "deletions": 1},
        "files": [{"path": "src/lib.rs"}, {"path": "tests/ui.rs"}],
        "truncated": false,
    });
    app.push_tool_result_with_call(
        diff,
        Some(ToolCall {
            call_id: "diff-1".to_string(),
            name: "diff_context".to_string(),
            arguments: serde_json::json!({}),
        }),
    );

    let mut glob = sample_tool_result("glob", "");
    glob.call_id = "glob-1".to_string();
    glob.content = serde_json::json!({
        "paths": ["src/lib.rs", "src/main.rs"],
        "metadata": {"pattern": "**/*.rs", "path": "."},
    });
    app.push_tool_result_with_call(
        glob,
        Some(ToolCall {
            call_id: "glob-1".to_string(),
            name: "glob".to_string(),
            arguments: serde_json::json!({"pattern": "**/*.rs"}),
        }),
    );

    let mut read = sample_tool_result("read_file", "");
    read.call_id = "read-1".to_string();
    read.content = serde_json::json!({
        "path": "src/lib.rs",
        "bytes_returned": 128,
        "total_bytes": 1024,
        "content": "fn main() {}",
        "truncated": true,
    });
    app.push_tool_result_with_call(
        read,
        Some(ToolCall {
            call_id: "read-1".to_string(),
            name: "read_file".to_string(),
            arguments: serde_json::json!({"path": "src/lib.rs"}),
        }),
    );

    // Each card now shows a short body preview by default (5-line head-
    // tail cap), so the rendered height is taller than the old empty-
    // body collapsed view — render at a height that fits all three cards.
    let output = render_to_string(&app, 180, 40);

    assert!(
        output.contains("✔ Explored diff context (worktree) · 2 files · +3 -1"),
        "{output}"
    );
    assert!(
        output.contains("✔ Explored list files matching **/*.rs · 2 paths"),
        "{output}"
    );
    assert!(
        output.contains("✔ Explored read src/lib.rs · 128B · partial result"),
        "{output}"
    );
    assert!(!output.contains("plan patch"), "{output}");
    assert!(!output.contains("output shortened"), "{output}");
    assert!(!output.contains("\"paths\""), "{output}");
}

