// ---------------------------------------------------------------------------
// Phase 1 — fullscreen terminal lifecycle (TerminalGuard).
//
// These exercise the byte-emitting seams the production guard now delegates to
// (`emit_terminal_enter_setup`, `emit_terminal_emergency_teardown`), the env
// policy resolver (`resolve_mouse_capture`), and the `draw_app` renderer
// routing — all against a headless `TerminalWriter::Capture` sink with a
// deterministic `FixedSize`, so there is no real TTY and no PTY.
// ---------------------------------------------------------------------------

/// True when a row carries a live composer horizon: a `☽` followed (after
/// optional spaces) by one of the horizon dash glyphs. Mirrors the term-matrix
/// `is_composer_horizon` matcher (which lives behind the `term-matrix` feature,
/// so it is re-encoded here for the default-feature lib tests).
fn row_is_composer_horizon(row: &str) -> bool {
    let dashes = ['─', '╌', '┈'];
    let mut chars = row.chars().peekable();
    while let Some(c) = chars.next() {
        if c != '☽' {
            continue;
        }
        let mut lookahead = chars.clone();
        while matches!(lookahead.peek(), Some(' ')) {
            lookahead.next();
        }
        if matches!(lookahead.peek(), Some(d) if dashes.contains(d)) {
            return true;
        }
    }
    false
}

fn sink_to_string(sink: &Arc<StdMutex<Vec<u8>>>) -> String {
    let bytes = sink.lock().expect("capture sink lock").clone();
    String::from_utf8(bytes).expect("captured ANSI is valid utf8")
}

/// Strip CSI / OSC escape sequences from a captured stream, leaving only the
/// glyphs that land on screen. ratatui positions each row with a `CUP`
/// (`\x1b[<row>;<col>H`) cursor move and styles cells with interleaved `SGR`
/// sequences rather than newlines, so the visible composer horizon (`☽───…`) is
/// only contiguous text once those escapes are removed.
fn strip_ansi(ansi: &str) -> String {
    let mut out = String::with_capacity(ansi.len());
    let mut chars = ansi.chars().peekable();
    while let Some(c) = chars.next() {
        if c != '\u{1b}' {
            out.push(c);
            continue;
        }
        match chars.peek() {
            // CSI: `\x1b[` … final byte in 0x40..=0x7e.
            Some('[') => {
                chars.next();
                for c in chars.by_ref() {
                    if ('\u{40}'..='\u{7e}').contains(&c) {
                        break;
                    }
                }
            }
            // OSC: `\x1b]` … terminated by BEL or ST (`\x1b\`).
            Some(']') => {
                chars.next();
                while let Some(c) = chars.next() {
                    if c == '\u{7}' {
                        break;
                    }
                    if c == '\u{1b}' {
                        if matches!(chars.peek(), Some('\\')) {
                            chars.next();
                        }
                        break;
                    }
                }
            }
            // Any other escape: drop the single following byte.
            _ => {
                chars.next();
            }
        }
    }
    out
}

#[test]
fn fullscreen_enter_emits_alt_screen_enter_sequence() {
    let mut bytes = Vec::new();
    emit_terminal_enter_setup(&mut bytes, /* mouse_capture = */ true)
        .expect("emit fullscreen enter setup");
    let ansi = String::from_utf8(bytes).expect("ansi");

    // The defining contract: fullscreen enters the alternate screen.
    assert!(
        ansi.contains("\x1b[?1049h"),
        "fullscreen enter must emit EnterAlternateScreen, got {ansi:?}"
    );
    // Alternate-scroll (wheel -> arrow keys) and bracketed paste / focus
    // reporting come up with it.
    assert!(
        ansi.contains("\x1b[?1007h"),
        "fullscreen enter must enable alternate-scroll"
    );
    // Mouse capture is on by default in fullscreen.
    assert!(
        ansi.contains(ENABLE_MOUSE_CLICK_CAPTURE),
        "fullscreen enter must enable mouse click capture by default"
    );
}

#[test]
fn fullscreen_enter_respects_mouse_capture_disabled() {
    let mut bytes = Vec::new();
    emit_terminal_enter_setup(&mut bytes, /* mouse_capture = */ false)
        .expect("emit fullscreen enter setup, mouse off");
    let ansi = String::from_utf8(bytes).expect("ansi");

    assert!(
        ansi.contains("\x1b[?1049h"),
        "fullscreen still enters the alternate screen with mouse capture off"
    );
    assert!(
        !ansi.contains(ENABLE_MOUSE_CLICK_CAPTURE),
        "SQUEEZY_MOUSE_CAPTURE=0 must suppress mouse click capture"
    );
}

#[test]
fn mouse_capture_defaults_on_unless_disabled() {
    // Default ON when the var is unset.
    assert!(
        resolve_mouse_capture(|_| None),
        "mouse capture defaults on when SQUEEZY_MOUSE_CAPTURE is unset"
    );
    // Only the literal "0" disables it.
    assert!(
        !resolve_mouse_capture(
            |key| (key == "SQUEEZY_MOUSE_CAPTURE").then(|| std::ffi::OsString::from("0"))
        ),
        "SQUEEZY_MOUSE_CAPTURE=0 disables mouse capture"
    );
    // Any other value (including empty) leaves it on.
    assert!(
        resolve_mouse_capture(
            |key| (key == "SQUEEZY_MOUSE_CAPTURE").then(|| std::ffi::OsString::from("1"))
        ),
        "SQUEEZY_MOUSE_CAPTURE=1 keeps mouse capture on"
    );
    assert!(
        resolve_mouse_capture(|key| (key == "SQUEEZY_MOUSE_CAPTURE").then(std::ffi::OsString::new)),
        "an empty SQUEEZY_MOUSE_CAPTURE value leaves mouse capture on"
    );
}

#[tokio::test]
async fn draw_app_routes_main_view_through_render() {
    let mut app = test_app(SessionMode::Build);
    app.push_transcript_item(TranscriptItem::assistant("hello from the model"));

    // draw_app drives the fullscreen `render()` path — the single renderer.
    let (mut guard, sink) = TerminalGuard::for_capture_test(120, 40);
    guard.draw_app(&mut app).expect("fullscreen draw_app");
    let ansi = sink_to_string(&sink);

    // The fullscreen frame rendered the main view, which pins the composer
    // horizon (`☽` + dashes) at the bottom. ratatui interleaves SGR escapes
    // between the moon coin and the dashes, so match on the de-escaped glyph
    // stream.
    let plain = strip_ansi(&ansi);
    assert!(
        row_is_composer_horizon(&plain),
        "fullscreen render() must draw the composer horizon main view"
    );
}

/// `\x1b[?2026h` / `\x1b[?2026l` — DEC 2026 synchronized-output begin/end. The
/// fullscreen renderer brackets each painted frame with these when synchronized
/// output is enabled so a capable terminal commits the frame's cells atomically.
const SYNC_BEGIN: &str = "\x1b[?2026h";
const SYNC_END: &str = "\x1b[?2026l";

#[tokio::test]
async fn fullscreen_draw_app_brackets_frame_in_synchronized_output_when_enabled() {
    // The Phase 8 sync-output guarantee on the PRODUCTION fullscreen path: when
    // synchronized output is enabled, the `Terminal::draw` is wrapped in DEC
    // 2026 begin/end so a capable terminal never shows a partially-painted
    // frame. Drive `draw_app` against the capture sink with the flag forced on
    // and assert the painted frame is bracketed, with BEGIN before END.
    let mut app = test_app(SessionMode::Build);
    app.push_transcript_item(TranscriptItem::assistant("hello from the model"));

    let (mut guard, sink) = TerminalGuard::for_capture_test(120, 40);
    guard.set_synchronized_output(true);
    guard.draw_app(&mut app).expect("fullscreen draw_app");
    let ansi = sink_to_string(&sink);

    let begin = ansi
        .find(SYNC_BEGIN)
        .expect("a synchronized fullscreen frame must open with the DEC 2026 begin marker");
    let end = ansi
        .rfind(SYNC_END)
        .expect("a synchronized fullscreen frame must close with the DEC 2026 end marker");
    assert!(
        begin < end,
        "the begin marker must precede the end marker so the frame is wrapped, \
         not the other way around"
    );
    // The actual frame content (the composer horizon main view) must land
    // BETWEEN the brackets, proving they surround the commit rather than sitting
    // adjacent to it.
    let between = &ansi[begin + SYNC_BEGIN.len()..end];
    assert!(
        row_is_composer_horizon(&strip_ansi(between)),
        "the painted frame must sit inside the synchronized-output brackets"
    );
}

#[tokio::test]
async fn fullscreen_draw_app_emits_no_synchronized_brackets_when_disabled() {
    // The default capture guard has synchronized output OFF; the fullscreen
    // frame must then emit no DEC 2026 brackets at all (the feature is opt-in by
    // terminal capability / user policy).
    let mut app = test_app(SessionMode::Build);
    app.push_transcript_item(TranscriptItem::assistant("hello from the model"));

    let (mut guard, sink) = TerminalGuard::for_capture_test(120, 40);
    guard.draw_app(&mut app).expect("fullscreen draw_app");
    let ansi = sink_to_string(&sink);

    assert!(
        !ansi.contains(SYNC_BEGIN) && !ansi.contains(SYNC_END),
        "synchronized output is opt-in: a disabled frame emits no DEC 2026 brackets"
    );
}

#[tokio::test]
async fn draw_app_stamps_render_metrics_for_a_painted_frame() {
    // Frame-budget instrumentation, end to end through the production
    // `draw_app` chokepoint: a painted frame must stamp a non-trivial metrics
    // snapshot — bytes actually emitted, rows built for the main view, and a
    // frame ordinal that advances.
    let mut app = test_app(SessionMode::Build);
    app.push_transcript_item(TranscriptItem::assistant(
        "hello from the model, a reasonably long line so the wrap does some work",
    ));

    let before = app.render_metrics.get();
    assert_eq!(before.frame, 0, "a fresh app has stamped no frames yet");

    let (mut guard, _sink) = TerminalGuard::for_capture_test(120, 40);
    guard.draw_app(&mut app).expect("fullscreen draw_app");

    let m = app.render_metrics.get();
    assert_eq!(m.frame, 1, "the first painted frame is frame #1");
    assert!(m.bytes_emitted > 0, "a painted frame emits bytes: {m:?}");
    assert!(
        m.rows_built > 0,
        "the main view materialized wrapped rows this frame: {m:?}"
    );
    // The second paint advances the ordinal, proving the stamp is per-frame.
    guard
        .draw_app(&mut app)
        .expect("second fullscreen draw_app");
    assert_eq!(
        app.render_metrics.get().frame,
        2,
        "each painted frame advances the frame ordinal"
    );
}

