#[test]
fn emergency_teardown_leaves_alt_screen_and_restores_modes_without_mirror() {
    let mut bytes = Vec::new();
    emit_terminal_emergency_teardown(&mut bytes, /* alt_screen_active = */ true)
        .expect("emit emergency teardown");
    let ansi = String::from_utf8(bytes).expect("ansi");

    // Leaves the alternate screen.
    let leave_pos = ansi
        .find("\x1b[?1049l")
        .expect("emergency teardown must leave the alternate screen");
    // Restores terminal modes: keyboard enhancement pop, bracketed paste off,
    // focus reporting off, mouse modes off, title cleared.
    assert!(
        ansi.contains(RESET_KEYBOARD_ENHANCEMENT_FLAGS),
        "teardown must reset keyboard enhancement flags"
    );
    assert!(
        ansi.contains(DISABLE_MOUSE_MODES),
        "teardown must disable mouse modes"
    );
    assert!(
        ansi.contains("\x1b[?2004l"),
        "teardown must disable bracketed paste"
    );
    // Mode restore happens AFTER leaving the alternate buffer so it lands on the
    // restored normal buffer.
    let reset_pos = ansi
        .find(RESET_KEYBOARD_ENHANCEMENT_FLAGS)
        .expect("teardown emits keyboard reset");
    assert!(
        reset_pos > leave_pos,
        "mode restore must come after LeaveAlternateScreen"
    );

    // Emergency teardown must NOT mirror the transcript or purge scrollback:
    // a clean exit owns the mirror; Drop only restores terminal state. The
    // scrollback-wipe `\x1b[3J` would destroy the user's pre-launch scrollback.
    assert!(
        !ansi.contains("\x1b[3J"),
        "emergency teardown must never purge scrollback (\\x1b[3J)"
    );
}

/// Phase 9 SIGTSTP (Ctrl+Z) suspend/resume — byte contract.
///
/// `TerminalGuard::suspend_and_resume` performs three steps around the actual
/// process-stop: (1) restore the terminal to a sane shell state, (2) re-raise
/// SIGTSTP (the real stop — not exercised here, it would stop the test process),
/// (3) on resume, re-enter the alternate screen + clear. Steps 1 and 3 reuse the
/// exact single-sourced emitters `emit_terminal_emergency_teardown` and
/// `emit_terminal_enter_setup`. This test pins that the SUSPEND restore leaves
/// the alternate screen + restores modes (no transcript mirror, no scrollback
/// purge), and the RESUME re-enter re-enters the alternate screen + clears — i.e.
/// the bytes the shell sees on Ctrl+Z and the bytes the user sees on `fg`, in
/// order.
#[test]
fn suspend_restores_terminal_then_resume_reenters_and_clears() {
    // Step 1 — suspend restore: the same emergency-teardown bytes, which leave
    // the alternate screen and restore terminal modes but write NO user content.
    let mut suspend_bytes = Vec::new();
    emit_terminal_emergency_teardown(&mut suspend_bytes, /* alt_screen_active = */ true)
        .expect("emit suspend restore");
    let suspend = String::from_utf8(suspend_bytes).expect("ansi");

    // Leaves the alternate screen so the shell that reclaims the terminal sees a
    // normal buffer.
    assert!(
        suspend.contains("\x1b[?1049l"),
        "suspend must leave the alternate screen before the process stops"
    );
    // Restores modes the shell needs back: mouse off, bracketed paste off.
    assert!(
        suspend.contains(DISABLE_MOUSE_MODES),
        "suspend must disable mouse modes"
    );
    assert!(
        suspend.contains("\x1b[?2004l"),
        "suspend must disable bracketed paste"
    );
    // Suspend is NOT a clean exit: it must never mirror the transcript or purge
    // the user's scrollback — `fg` should drop the user right back into the TUI.
    assert!(
        !suspend.contains("\x1b[3J"),
        "suspend must never purge scrollback (\\x1b[3J)"
    );

    // Step 3 — resume re-enter: the same enter-setup bytes (fullscreen, mouse on).
    let mut resume_bytes = Vec::new();
    emit_terminal_enter_setup(&mut resume_bytes, /* mouse_capture = */ true)
        .expect("emit resume re-enter");
    let resume = String::from_utf8(resume_bytes).expect("ansi");

    // Re-enters the alternate screen and clears it (blank on re-entry).
    assert!(
        resume.contains("\x1b[?1049h"),
        "resume must re-enter the alternate screen"
    );
    assert!(
        resume.contains("\x1b[2J") || resume.contains("\x1b[3J") || resume.contains("\x1b[H"),
        "resume must clear/home the freshly re-entered alternate screen"
    );
    // Mouse capture and alternate-scroll come back up with the re-enter.
    assert!(
        resume.contains(ENABLE_MOUSE_CLICK_CAPTURE),
        "resume must re-enable mouse click capture"
    );
    assert!(
        resume.contains("\x1b[?1007h"),
        "resume must re-enable alternate-scroll"
    );
}

/// Phase 9 SIGTSTP resume — forced full redraw from model state.
///
/// After `SIGCONT` the freshly re-entered alternate screen is blank and
/// ratatui's incremental diff cannot be trusted, so resume marks the app so the
/// very next loop frame repaints EVERYTHING: `needs_redraw` forces a draw past
/// the idle-skip gate and `pending_resize` forces it past the frame-limiter
/// wants-draw gate (and re-anchors scroll geometry in case the window was resized
/// while suspended). `mark_full_redraw_after_resume` is the factored-out contract
/// `suspend_and_resume` calls after re-entering; this drives it directly so the
/// forced-redraw guarantee is pinned without the Unix-only blocking re-raise.
#[test]
fn resume_marks_app_for_full_redraw() {
    let mut app = test_app(SessionMode::Build);
    // Start from a "clean / nothing pending" state to prove resume sets both.
    app.needs_redraw = false;
    app.pending_resize = false;

    mark_full_redraw_after_resume(&mut app);

    assert!(
        app.needs_redraw,
        "resume must trigger a redraw (the idle-skip gate reads `needs_redraw`)"
    );
    assert!(
        app.pending_resize,
        "resume must flag a pending resize so scroll geometry is re-anchored \
         (the size may have changed in the shell while suspended)"
    );
    // The re-anchor side effect: `mark_full_redraw_after_resume` snaps any
    // in-flight ease, so no smooth-scroll animation lingers across the resume.
    assert!(
        app.main_scroll_anim.is_none(),
        "resume must cancel any in-flight main-scroll ease (its start is stale)"
    );
}

// ---------------------------------------------------------------------------
// Terminal Restore Command (§12.9.2).
//
// The recovery verb that forcibly returns a wedged terminal to a sane state
// (leave alt-screen, reset modes, show cursor, disable raw mode) and re-enters
// the fullscreen surface. Both the `Ctrl+Alt+,` keybinding and the
// `/terminal-reset` slash command flag the request on the model; the run loop
// drains it on the guard. These drive the real dispatch + the real guard against
// a `TerminalWriter::Capture` sink — no real TTY.
// ---------------------------------------------------------------------------

/// `Ctrl+Alt+,` — the default Terminal Restore Command verb.
fn ctrl_alt_comma() -> KeyEvent {
    KeyEvent::new(
        KeyCode::Char(','),
        KeyModifiers::CONTROL | KeyModifiers::ALT,
    )
}

#[tokio::test]
async fn keyboard_ctrl_alt_comma_queues_a_terminal_restore() {
    let mut app = test_app(SessionMode::Build);
    let mut agent = test_agent(SessionMode::Build);
    assert!(
        !app.pending_terminal_restore.is_pending(),
        "no restore is queued at rest",
    );

    let consumed = dispatch_keymap_action(&mut app, &mut agent, ctrl_alt_comma());
    assert!(consumed, "Ctrl+Alt+, is consumed by the keymap dispatch");
    assert!(
        app.pending_terminal_restore.is_pending(),
        "the keyboard verb queues the restore for the run loop to drain",
    );
    // The verb is responsive: an in-flight status shows on the frame before the
    // loop runs the recovery, and a redraw is requested so the loop wakes.
    assert!(
        app.status.contains("restoring terminal"),
        "an in-flight status is shown: {}",
        app.status,
    );
    assert!(
        app.needs_redraw,
        "a redraw wakes the loop to drain the request"
    );
}

fn ctrl_alt_slash() -> KeyEvent {
    KeyEvent::new(
        KeyCode::Char('/'),
        KeyModifiers::CONTROL | KeyModifiers::ALT,
    )
}

#[tokio::test]
async fn keyboard_ctrl_alt_slash_toggles_layout_fallback_diagnostics() {
    // §12.9.3 keyboard path: the diagnostics toggle flips the hidden flag, forces
    // the render-metrics HUD visible (the line rides inside it), and requests a
    // redraw so the change shows immediately.
    let mut app = test_app(SessionMode::Build);
    let mut agent = test_agent(SessionMode::Build);
    assert!(
        !app.show_layout_fallback,
        "the diagnostics line is off at rest",
    );

    let consumed = dispatch_keymap_action(&mut app, &mut agent, ctrl_alt_slash());
    assert!(consumed, "Ctrl+Alt+/ is consumed by the keymap dispatch");
    assert!(
        app.show_layout_fallback,
        "the keyboard verb flips the diagnostics line on",
    );
    assert!(
        app.show_render_metrics,
        "turning the line on forces the render-metrics HUD it rides inside visible",
    );
    assert!(app.needs_redraw, "a redraw shows the change immediately");

    // A second press toggles it back off; the HUD flag is sticky (the user may
    // have wanted it), matching the latency / dogfood toggles.
    assert!(dispatch_keymap_action(
        &mut app,
        &mut agent,
        ctrl_alt_slash()
    ));
    assert!(
        !app.show_layout_fallback,
        "a second press toggles the diagnostics line back off",
    );
}

#[test]
fn render_records_a_last_known_good_layout_for_a_normal_frame() {
    // §12.9.3 render path: a normal (non-degenerate) frame painted through the
    // real `render()` records its geometry as the last-known-good snapshot, keyed
    // by the rendered size, and never trips the fallback.
    let app = test_app(SessionMode::Build);
    assert_eq!(
        app.layout_fallback.good(),
        None,
        "nothing recorded pre-paint"
    );

    let _ = render_to_string(&app, 100, 30);

    let good = app
        .layout_fallback
        .good()
        .expect("a normal frame records a last-known-good snapshot");
    assert_eq!(
        (good.width, good.height),
        (100, 30),
        "the snapshot is keyed by the rendered size",
    );
    assert!(
        good.input_height > 0,
        "the recorded good frame reserves a composer row",
    );
    assert!(
        !good.is_degenerate(),
        "the recorded snapshot is a valid (non-degenerate) layout",
    );
    assert_eq!(
        app.layout_fallback.fallback_count(),
        0,
        "a normal frame never falls back",
    );
}

#[test]
fn layout_fallback_diagnostics_line_paints_in_the_real_render_hud() {
    // §12.9.3 render path: with the diagnostics line toggled on, the real
    // `render()` paints the fallback status inside the render-metrics HUD, keyed
    // by the rendered size.
    let mut app = test_app(SessionMode::Build);
    app.toggle_layout_fallback_diagnostics();
    assert!(app.show_layout_fallback && app.show_render_metrics);

    let output = render_to_string(&app, 120, 30);
    assert!(
        output.contains("layout-fallback:"),
        "the diagnostics line paints inside the HUD:\n{output}",
    );
    assert!(
        output.contains("good=120x30"),
        "the painted line reports the good-snapshot size:\n{output}",
    );
    assert!(
        output.contains("falls=0"),
        "a healthy session reports zero fallbacks:\n{output}",
    );
}

#[test]
fn render_records_good_per_size_across_a_resize() {
    // §12.9.3 size seam: re-rendering at a new size records a fresh good snapshot
    // keyed by the new size, so a resize never strands the prior geometry.
    let app = test_app(SessionMode::Build);
    let _ = render_to_string(&app, 80, 24);
    assert_eq!(
        app.layout_fallback.good().map(|g| (g.width, g.height)),
        Some((80, 24)),
    );

    // Resize: a wider/taller frame becomes the new last-known-good.
    let _ = render_to_string(&app, 140, 40);
    assert_eq!(
        app.layout_fallback.good().map(|g| (g.width, g.height)),
        Some((140, 40)),
        "the good snapshot tracks the latest rendered size",
    );
    assert_eq!(
        app.layout_fallback.fallback_count(),
        0,
        "two normal frames at different sizes never fall back",
    );
}

