#[test]
fn exit_mirror_link_survives_a_narrow_resize_clip() {
    // Resize where the feature paints: a width so narrow the URL wraps/clips.
    // The emitter must still balance every OSC 8 open with a close (an
    // unbalanced open would leak the link onto the following scrollback rows).
    let mut app = test_app(SessionMode::Build);
    app.push_transcript_item(TranscriptItem::assistant(
        "link https://example.test/a/very/long/path/that/wraps/around",
    ));

    // A deliberately tight width forces the URL across wrapped rows.
    let width = 20u16;
    let mirror = mirror_buffer_for(&app, width);

    let mut bytes = Vec::new();
    emit_finish_fullscreen(
        &mut bytes,
        &mirror,
        width,
        None,
        hyperlinks::HyperlinkCapabilities::enabled(),
    )
    .expect("emit finish_fullscreen");
    let ansi = String::from_utf8(bytes).expect("ansi");

    // Every OSC 8 open must have a matching close: count the opens (prefix
    // occurrences that are NOT the close form) and the closes, and require the
    // closes to be at least the opens so no run is left dangling.
    let opens = ansi.matches(OSC8_OPEN_PREFIX).count();
    let closes = ansi.matches(OSC8_CLOSE).count();
    // Each close also begins with the open prefix, so closes are counted within
    // `opens`; the real open count is `opens - closes`, and that must be > 0
    // (the URL did link) and <= closes (every open is balanced).
    let real_opens = opens - closes;
    assert!(real_opens > 0, "the wrapped URL still links: {ansi:?}");
    assert!(
        closes >= real_opens,
        "every OSC 8 open ({real_opens}) must be balanced by a close ({closes}): {ansi:?}",
    );
}

#[test]
fn toggle_hyperlinks_cycles_auto_on_off_and_back() {
    // The keyboard verb cycles the override: auto (probe) -> on -> off -> auto.
    let mut app = test_app(SessionMode::Build);
    // Force a known probe so `auto` is deterministic regardless of the CI env.
    app.hyperlink_caps = hyperlinks::HyperlinkCapabilities::disabled();
    assert_eq!(app.hyperlink_override, None, "starts in auto (deferring)");
    assert!(
        !app.effective_hyperlink_caps().osc8,
        "auto over an incapable probe is off"
    );

    toggle_hyperlinks(&mut app);
    assert_eq!(app.hyperlink_override, Some(true), "auto -> on");
    assert!(app.effective_hyperlink_caps().osc8, "forced on");
    assert!(
        app.status.contains("hyperlinks"),
        "status reflects the mode"
    );

    toggle_hyperlinks(&mut app);
    assert_eq!(app.hyperlink_override, Some(false), "on -> off");
    assert!(!app.effective_hyperlink_caps().osc8, "forced off");

    toggle_hyperlinks(&mut app);
    assert_eq!(app.hyperlink_override, None, "off -> auto");
    assert!(
        !app.effective_hyperlink_caps().osc8,
        "back to auto, deferring to the incapable probe"
    );
}

#[test]
fn effective_caps_force_on_over_an_incapable_probe() {
    let mut app = test_app(SessionMode::Build);
    app.hyperlink_caps = hyperlinks::HyperlinkCapabilities::disabled();
    app.hyperlink_override = Some(true);
    assert!(
        app.effective_hyperlink_caps().osc8,
        "an explicit force-on beats an incapable probe",
    );
    app.hyperlink_override = Some(false);
    app.hyperlink_caps = hyperlinks::HyperlinkCapabilities::enabled();
    assert!(
        !app.effective_hyperlink_caps().osc8,
        "an explicit force-off beats a capable probe",
    );
}

#[tokio::test]
async fn hyperlinks_keymap_chord_toggles_through_dispatch() {
    // Keyboard path: the Alt+8 keymap action drives the toggle through the real
    // dispatch, the same routing a rebound key would take.
    let mut app = test_app(SessionMode::Build);
    let mut agent = test_agent(SessionMode::Build);
    assert_eq!(app.hyperlink_override, None);
    let chord = KeyEvent::new(KeyCode::Char('8'), KeyModifiers::ALT);
    let consumed = dispatch_keymap_action(&mut app, &mut agent, chord);
    assert!(
        consumed,
        "the Alt+8 chord is consumed by the keymap dispatch"
    );
    assert_eq!(
        app.hyperlink_override,
        Some(true),
        "Alt+8 advances auto -> on through dispatch",
    );
}

#[test]
fn toggling_hyperlinks_requests_no_idle_repaint() {
    // The mode only affects the persisted exit-mirror, not any live frame, so
    // the toggle must NOT set needs_redraw — idle redraw stays zero.
    let mut app = test_app(SessionMode::Build);
    app.needs_redraw = false;
    toggle_hyperlinks(&mut app);
    assert!(
        !app.needs_redraw,
        "a hyperlink-mode toggle paints no live frame, so it requests no repaint",
    );
}

#[test]
fn emergency_drop_teardown_emits_no_transcript_mirror() {
    // The emergency (`Drop`) teardown restores terminal state only: it must never
    // mirror transcript content. Distinct from the clean-exit path, which owns
    // the mirror. We assert no CRLF-mirrored text rides along the teardown bytes.
    let mut bytes = Vec::new();
    emit_terminal_emergency_teardown(&mut bytes, /* alt_screen_active = */ true)
        .expect("emit emergency teardown");
    let ansi = String::from_utf8(bytes).expect("ansi");

    // It leaves the alt screen (still in it) but writes no normal-buffer history:
    // there are no CRLF row terminators (the mirror's row separator) at all.
    assert!(
        ansi.contains(LEAVE_ALT_SCREEN),
        "emergency teardown still leaves the alternate screen when in it",
    );
    assert!(
        !ansi.contains("\r\n"),
        "emergency teardown is mirror-free: no CRLF transcript rows, got {ansi:?}",
    );
    assert!(
        !ansi.contains("\x1b[3J"),
        "emergency teardown must never purge scrollback",
    );

    // Full lifecycle proof through the real `Drop`: build a fullscreen guard on a
    // capture sink with a settled transcript reachable to the renderer, drop it,
    // and confirm no transcript text was mirrored by the emergency path.
    let (guard, sink) = TerminalGuard::for_capture_test(80, 24);
    drop(guard);
    let drop_ansi = sink_to_string(&sink);
    assert!(
        drop_ansi.contains(LEAVE_ALT_SCREEN),
        "dropping a fullscreen guard leaves the alternate screen",
    );
    assert!(
        !drop_ansi.contains("\x1b[3J"),
        "Drop must not purge the user's pre-launch scrollback",
    );
}

/// `buffer_used_height` returns 0 for a wholly-blank buffer (a blank cell is a
/// space, default background, and no modifiers). This anchors the empty case
/// that feeds the `.max(1)` clamp in `render_lines_to_owned_buffer`.
#[test]
fn buffer_used_height_all_blank_is_zero() {
    let buf = Buffer::empty(Rect::new(0, 0, 8, 4));
    assert_eq!(
        buffer_used_height(&buf),
        0,
        "an all-blank buffer has no used rows"
    );
}

/// Content on the LAST row makes the used height span the whole buffer — no
/// trailing blank rows exist below it to trim.
#[test]
fn buffer_used_height_content_on_last_row_is_full_height() {
    let mut buf = Buffer::empty(Rect::new(0, 0, 8, 4));
    buf.set_string(0, 3, "hi", Style::default()); // last row (y = 3)
    assert_eq!(
        buffer_used_height(&buf),
        4,
        "content on the last row means the full height is used"
    );
}

/// Trailing blank rows below the last content row are trimmed: content on row 1
/// of a 5-row buffer yields a used height of 2.
#[test]
fn buffer_used_height_trims_trailing_blank_rows() {
    let mut buf = Buffer::empty(Rect::new(0, 0, 8, 5));
    buf.set_string(0, 1, "x", Style::default()); // y = 1; rows 2..5 stay blank
    assert_eq!(
        buffer_used_height(&buf),
        2,
        "trailing blank rows are dropped; used height stops after row 1"
    );
}

/// The blank predicate also requires `modifier == Modifier::empty()`, so a row of
/// spaces that carries a non-empty modifier (with the default background) counts
/// as content — its used height is NOT trimmed away.
#[test]
fn buffer_used_height_space_with_modifier_counts_as_content() {
    let mut buf = Buffer::empty(Rect::new(0, 0, 8, 3));
    // Row 1: spaces only, default background, but a non-empty modifier.
    let cell = buf.cell_mut((0, 1)).expect("cell in bounds");
    assert_eq!(cell.symbol(), " ", "cell starts as a blank space");
    cell.modifier = Modifier::BOLD;
    assert_eq!(cell.bg, Color::Reset, "background stays the default");
    assert_eq!(
        buffer_used_height(&buf),
        2,
        "a space-only row with a modifier is content, not blank"
    );
}

/// `render_lines_to_owned_buffer` clamps to at least one row even when fed empty
/// or all-blank input, so the `.max(1)` never produces a zero-height buffer.
#[test]
fn render_lines_to_owned_buffer_clamps_empty_input_to_one_row() {
    // No lines at all.
    let empty: Vec<Line<'static>> = Vec::new();
    let buf = render_lines_to_owned_buffer(&empty, 12);
    assert_eq!(
        buf.area.height, 1,
        "empty input clamps to a single-row buffer"
    );

    // All-blank lines (whitespace only) — used height would be 0 without the clamp.
    let blank = vec![
        Line::from(vec![Span::raw("   ")]),
        Line::from(vec![Span::raw("")]),
    ];
    let buf = render_lines_to_owned_buffer(&blank, 12);
    assert_eq!(
        buf.area.height, 1,
        "all-blank lines clamp to a single-row buffer"
    );
}

/// Finding-1 height fix: `visual_line_count`'s `chars().count().div_ceil(width)`
/// estimate UNDER-counts a logical line that (a) word-wraps a too-long word and
/// (b) contains wide CJK glyphs measured as one column but rendered as two. The
/// clean-exit mirror sizes its buffer with `render_lines_to_owned_buffer`, which
/// gets the exact wrapped-row count from `Paragraph::line_count`, so EVERY
/// wrapped row is emitted; the old estimate would clip the overflow rows and
/// truncate mirrored history.
#[test]
fn finish_fullscreen_mirror_height_covers_wrapped_rows_not_visual_estimate() {
    // Width 10. The line forces both pathologies:
    //   * a 22-char unbreakable word ("aaaa…") that word-wraps across rows, and
    //   * eight wide CJK glyphs (好, 2 columns each = 16 display cols) that the
    //     char-count estimate sees as 8 columns.
    let width = 10u16;
    let long_word = "a".repeat(22);
    let cjk = "好".repeat(8);
    let content = format!("{long_word} {cjk}");
    let line = Line::from(vec![Span::raw(content.clone())]);
    let lines = vec![line.clone()];

    // The under-counting estimate the OLD mirror height used.
    let estimate = visual_line_count(&lines, width) as usize;

    // Ground truth: render the same word-wrapping `Paragraph` into a generously
    // tall buffer and count the rows that actually carry glyphs.
    let tall = {
        let mut buf = Buffer::empty(Rect::new(0, 0, width, 64));
        Paragraph::new(lines.clone())
            .wrap(Wrap { trim: false })
            .render(buf.area, &mut buf);
        buffer_used_height(&buf) as usize
    };
    assert!(
        tall > estimate,
        "test fixture must actually exceed the char-count estimate \
         (wrapped rows {tall} vs visual_line_count {estimate})",
    );

    // The mirror buffer the clean-exit path builds must be tall enough to hold
    // every wrapped row — never the under-counting estimate.
    let mirror = render_lines_to_owned_buffer(&lines, width);
    assert_eq!(
        mirror.area.height as usize, tall,
        "mirror buffer height must equal the true wrapped-row count, not the estimate",
    );
    assert!(
        (mirror.area.height as usize) > estimate,
        "mirror height {} must exceed the under-counting visual_line_count {estimate}",
        mirror.area.height,
    );

    // Emit the mirror and prove NO row was truncated: every glyph of the original
    // content survives across the wrapped rows. Strip the styling escapes, drop
    // CRLFs, and the de-wrapped text must contain the long word and all CJK.
    let mut bytes = Vec::new();
    emit_finish_fullscreen(
        &mut bytes,
        &mirror,
        width,
        None,
        hyperlinks::HyperlinkCapabilities::disabled(),
    )
    .expect("emit finish_fullscreen");
    let ansi = String::from_utf8(bytes).expect("ansi");
    let visible: String = strip_ansi(&ansi)
        .chars()
        .filter(|c| *c != '\r' && *c != '\n')
        .collect();
    assert!(
        visible.contains(&long_word),
        "the wrapped long word must survive every row, none clipped: {visible:?}",
    );
    assert!(
        visible.contains(&cjk),
        "every wide CJK glyph must survive the wrap, none clipped: {visible:?}",
    );
}

/// Driver-level clean-exit test: drive a settled session through the real
/// `finish_fullscreen` against the `for_capture_test` `Capture` seam, then assert
/// on the captured byte stream that `LeaveAlternateScreen` precedes the mirrored
/// response text — the end-to-end form of the byte-order contract.
#[test]
fn clean_exit_mirror() {
    // A settled session: a user turn and a committed assistant response.
    let mut app = test_app(SessionMode::Build);
    app.push_transcript_item(TranscriptItem::user("summarize the change"));
    app.push_transcript_item(TranscriptItem::assistant(
        "Renamed the helper and updated its callers.",
    ));

    // Fullscreen guard on a capture sink at a deterministic size; its injected
    // `FixedSize` feeds `finish_fullscreen`'s width with no real TTY.
    let (mut guard, sink) = TerminalGuard::for_capture_test(100, 40);
    guard.set_exit_hint(Some("Resume: squeezy sessions resume deadbeef".to_string()));
    guard
        .finish_fullscreen(&app)
        .expect("clean exit mirrors the settled transcript");

    let ansi = sink_to_string(&sink);

    let leave_pos = ansi
        .find(LEAVE_ALT_SCREEN)
        .expect("clean exit must leave the alternate screen");
    let response_pos = ansi
        .find("Renamed the helper and updated its callers.")
        .expect("clean exit must mirror the committed assistant response");
    assert!(
        leave_pos < response_pos,
        "LeaveAlternateScreen (offset {leave_pos}) must precede the mirrored response \
         text (offset {response_pos}) so the mirror lands in real scrollback",
    );
    // The mirror landed in real scrollback, not the alt screen, and the resume
    // hint persisted after it.
    let hint_pos = ansi
        .find("squeezy sessions resume deadbeef")
        .expect("resume hint persisted after the mirror");
    assert!(
        response_pos < hint_pos,
        "the resume hint must follow the mirrored response",
    );
    // A clean exit never purges the user's pre-launch scrollback.
    assert!(
        !ansi.contains("\x1b[3J"),
        "clean exit must not purge scrollback (\\x1b[3J)",
    );

    // Idempotence: a second `finish_fullscreen` short-circuits (alt screen already
    // left) and emits nothing further.
    let len_before = sink.lock().expect("sink lock").len();
    guard
        .finish_fullscreen(&app)
        .expect("second finish_fullscreen is a no-op");
    let len_after = sink.lock().expect("sink lock").len();
    assert_eq!(
        len_before, len_after,
        "a second clean exit must short-circuit and emit no further bytes",
    );
}

/// Deep-review #67: the clean-exit driver must RESTORE the terminal — leave the
/// alternate screen AND emit every mode restore — BEFORE it builds and prints the
/// heavy collapsed-transcript mirror, so an alloc-failure abort while allocating
/// the mirror buffer still leaves the user in a restored normal buffer rather than
/// stranded in a raw alternate screen. We assert the load-bearing ordering
/// invariant on the captured byte stream: every terminal-restore byte (the
/// `LeaveAlternateScreen` and the final title-reset mode restore) precedes the
/// first mirror row. Pre-fix the mode restores trailed the mirror (built first,
/// restores emitted last); post-fix they lead it.
#[test]
fn finish_fullscreen_restores_terminal_before_building_the_mirror() {
    let mut app = test_app(SessionMode::Build);
    app.push_transcript_item(TranscriptItem::user("summarize the change"));
    app.push_transcript_item(TranscriptItem::assistant(
        "Renamed the helper and updated its callers.",
    ));

    let (mut guard, sink) = TerminalGuard::for_capture_test(100, 40);
    guard
        .finish_fullscreen(&app)
        .expect("clean exit mirrors the settled transcript");
    let ansi = sink_to_string(&sink);

    // The first mirror row is the earliest user-facing scrollback text.
    let mirror_pos = ansi
        .find("Renamed the helper and updated its callers.")
        .expect("clean exit must mirror the committed assistant response");
    // Leave-alt-screen is a terminal-restore byte and must precede the mirror.
    let leave_pos = ansi
        .find(LEAVE_ALT_SCREEN)
        .expect("clean exit must leave the alternate screen");
    assert!(
        leave_pos < mirror_pos,
        "LeaveAlternateScreen (offset {leave_pos}) must precede the first mirror row \
         (offset {mirror_pos})",
    );
    // The title-reset `\x1b]0;\x07` is the LAST mode-restore byte. It is emitted
    // by the restore half, so it too must land before the mirror — proving the
    // whole restore sequence (not just the leave) completes before the heavy
    // mirror is built and printed.
    let title_reset_pos = ansi
        .find("\x1b]0;\x07")
        .expect("clean exit must reset the terminal title as part of the restore");
    assert!(
        title_reset_pos < mirror_pos,
        "the title-reset mode restore (offset {title_reset_pos}) must precede the \
         first mirror row (offset {mirror_pos}) so the terminal is fully restored \
         before the heavy mirror allocation",
    );
}

#[test]
fn transcript_render_wraps_long_shell_cards_on_the_rail() {
    let mut app = test_app(SessionMode::Build);
    let command = concat!(
        "echo \"=== .mcp.json ===\"; cat .mcp.json; echo; ",
        "echo \"=== .codex/hooks.json ===\"; cat .codex/hooks.json; echo; ",
        "echo \"=== squeezy on PATH? ===\";\n",
        "command -v squeezy || echo \"no squeezy binary\"; echo; ",
        "echo \"=== docker? ===\"; command -v docker || echo \"no docker\""
    );
    let call = ToolCall {
        call_id: "shell-1".to_string(),
        name: "shell".to_string(),
        arguments: serde_json::json!({"command": command}),
    };
    let mut result = sample_tool_result("shell", "");
    result.call_id = "shell-1".to_string();
    result.content = serde_json::json!({
        "command": command,
        "workdir": ".",
        "exit_code": 0,
        "stdout": "ok",
        "stderr": "",
    });
    app.push_tool_result_with_call(result, Some(call));
    app.finalize_settles_for_test();

    let width = 72usize;
    let lines = transcript_lines_for_render(&app, Some(width as u16), false);
    let rendered = lines_to_plain_text(&lines);

    assert!(rendered.contains("├─✔ Ran echo"), "{rendered}");
    assert!(
        rendered.lines().all(|line| line.chars().count() <= width),
        "flushed shell card must be pre-wrapped before terminal scrollback insertion:\n{rendered}"
    );
    assert!(
        rendered.lines().any(|line| line.starts_with("   │")),
        "wrapped continuation should stay on the rail:\n{rendered}"
    );
}

#[test]
fn transcript_render_wraps_representative_rail_nodes_to_width() {
    let mut app = test_app(SessionMode::Build);
    app.push_reasoning_segment(squeezy_core::ReasoningSnapshot::from_payload(
        squeezy_core::ReasoningPayload::OpenAi {
            item_id: "rsn-rail-wrap".to_string(),
            summary: vec![format!(
                "Plan: inspect {} and keep every continuation aligned",
                "formatting-spill-risk ".repeat(4)
            )],
            encrypted_content: None,
        },
    ));
    app.push_tool_result(sample_tool_result(
        "grep",
        &format!("match {}", "alpha-beta-gamma ".repeat(8)),
    ));
    app.push_tool_result(sample_tool_result("grep", &"x".repeat(140)));
    app.push_warn(format!(
        "configuration warning {}",
        "long-soft-wrap ".repeat(8)
    ));
    app.push_subagent_note(format!(
        "delegate subagent completed {}",
        "long-summary-fragment ".repeat(8)
    ));
    let mut failed = sample_tool_result("shell", "");
    failed.status = ToolStatus::Error;
    failed.content = serde_json::json!({
        "command": format!("cargo test {}", "--workspace ".repeat(8)),
        "workdir": ".",
        "exit_code": 1,
        "stdout": "",
        "stderr": format!("error: {}", "unbroken_error_token_".repeat(8)),
    });
    app.push_tool_result(failed);
    app.finalize_settles_for_test();

    let width = 54usize;
    let lines = transcript_lines_for_render(&app, Some(width as u16), false);
    let rendered = lines_to_plain_text(&lines);

    assert!(rendered.contains("reasoning"), "{rendered}");
    assert!(rendered.contains("configuration warning"), "{rendered}");
    assert!(
        rendered.contains("delegate subagent completed"),
        "{rendered}"
    );
    assert!(rendered.contains("Failed cargo test"), "{rendered}");
    assert!(
        rendered.lines().all(|line| line.chars().count() <= width),
        "every flushed rail row must fit before terminal insertion:\n{rendered}"
    );
    for line in rendered.lines().filter(|line| !line.is_empty()) {
        assert!(
            line.starts_with("   │") || line.starts_with("   ├"),
            "rail row should keep content out of the gutter: {line:?}\n{rendered}"
        );
    }
}

#[test]
fn cancelled_turn_render_persists_closing_moon_after_warn_tail() {
    let mut app = test_app(SessionMode::Build);
    app.push_transcript_item(TranscriptItem::user("What is the architecture?"));
    app.push_note("mcp status 0/1 ready 0 tools 1 failed".to_string());
    app.push_warn("turn cancelled".to_string());
    complete_turn_for_test(&mut app, TurnVisualState::Cancelled, Duration::from_secs(5));

    // The full fullscreen frame composes the transcript surface (warn tail) and
    // the completed-turn footer (the closing moon) the user actually sees.
    let rendered = render_to_string(&app, 100, 18);

    assert!(rendered.contains("turn cancelled"), "{rendered}");
    assert!(
        rendered.contains("╰─☽ Cancelled after 5s"),
        "the rendered frame must persist the cyan closed moon as the turn terminator: {rendered}"
    );
    // The warn tail must thread into the closing moon — the rail node row must
    // not be the last non-blank rail glyph (no dangling `│` connector).
    let warn_line = rendered
        .lines()
        .position(|l| l.contains("turn cancelled"))
        .expect("warn tail row present");
    let moon_line = rendered
        .lines()
        .position(|l| l.contains("╰─☽ Cancelled after 5s"))
        .expect("closing moon row present");
    assert!(
        moon_line > warn_line,
        "the closing moon must follow the warn tail, threading the rail:\n{rendered}"
    );
}

#[test]
fn fullscreen_transcript_inserts_pending_turn_divider_before_queued_prompt_for_all_outcomes() {
    for (visual, expected, color, expect_closing_moon) in [
        (
            TurnVisualState::Succeeded,
            "─ Worked for 4s",
            crate::render::theme::green(),
            false,
        ),
        (
            TurnVisualState::Failed,
            "╰─☽ Failed after 4s",
            crate::render::theme::red(),
            true,
        ),
        (
            TurnVisualState::Cancelled,
            "╰─☽ Cancelled after 4s",
            crate::render::theme::cyan(),
            true,
        ),
    ] {
        let mut app = test_app(SessionMode::Build);
        app.push_transcript_item(TranscriptItem::user("first prompt"));
        complete_turn_for_test(&mut app, visual, Duration::from_secs(4));

        app.note_turn_started();
        app.push_transcript_item(TranscriptItem::user("queued prompt"));

        let lines = transcript_lines_for_render(&app, Some(120), false);
        let rendered_lines = lines.iter().map(rendered_line_text).collect::<Vec<_>>();
        let divider_index = rendered_lines
            .iter()
            .position(|line| line.contains(expected))
            .expect("divider should render");
        let queued_prompt_index = rendered_lines
            .iter()
            .position(|line| line.contains("queued prompt"))
            .expect("queued prompt should render");
        assert!(
            divider_index < queued_prompt_index,
            "fullscreen transcript must show the completed-turn footer before the queued prompt:\n{}",
            rendered_lines.join("\n")
        );
        assert_eq!(
            rendered_lines
                .iter()
                .filter(|line| line.contains(expected))
                .count(),
            1,
            "fullscreen transcript should render exactly one completed divider:\n{}",
            rendered_lines.join("\n")
        );
        assert_eq!(lines[divider_index].spans[2].style.fg, Some(color));
        assert_eq!(
            rendered_lines[divider_index].contains("╰─☽"),
            expect_closing_moon,
            "{}",
            rendered_lines.join("\n")
        );
    }
}

