#[tokio::test]
async fn jump_nav_with_no_target_leaves_scroll_untouched() {
    let mut agent = test_agent(SessionMode::Build);
    let mut app = app_with_user_turns(40);
    // No assistant/tool/error entries exist; each such jump must be a no-op.
    let before = app.transcript_scroll;
    for key in [
        KeyEvent::new(KeyCode::Left, KeyModifiers::ALT), // prev assistant
        KeyEvent::new(KeyCode::Right, KeyModifiers::ALT), // next assistant
        KeyEvent::new(KeyCode::Char(','), KeyModifiers::ALT), // prev tool
        KeyEvent::new(KeyCode::Char('.'), KeyModifiers::ALT), // next tool
        KeyEvent::new(KeyCode::Char('['), KeyModifiers::ALT), // prev error
        KeyEvent::new(KeyCode::Char(']'), KeyModifiers::ALT), // next error
    ] {
        let _ = handle_key(&mut app, &mut agent, key).await.expect("jump");
        assert_eq!(
            app.transcript_scroll, before,
            "a jump with no matching target must not move the scroll state",
        );
    }
}

// ---- scrollbar click-to-jump mapping ------------------------------------

#[test]
fn main_scrollbar_click_maps_middle_of_track_to_middle_of_content() {
    let app = test_app(SessionMode::Build);
    // A 10-row gutter over 110 rows of content (viewport 10 => max_from_bottom
    // 100). Mid-track should map near the middle of the scroll range.
    app.main_scrollbar_cache.set(Some(MainScrollbarCache {
        scrollbar_area: Rect::new(39, 0, 1, 10),
        total_rows: 110,
        viewport_h: 10,
        max_from_bottom: 100,
    }));
    let top = main_scrollbar_from_bottom_from_mouse(&app, 39, 0).expect("top hit");
    let bottom = main_scrollbar_from_bottom_from_mouse(&app, 39, 9).expect("bottom hit");
    let middle = main_scrollbar_from_bottom_from_mouse(&app, 39, 5).expect("mid hit");
    assert_eq!(top, 100, "top of the track jumps to the top of the content");
    assert_eq!(bottom, 0, "bottom of the track pins to the tail");
    assert!(
        middle > bottom && middle < top,
        "a mid-track click lands between the tail and the top (got {middle})",
    );
    // Monotonic: lower in the track ⇒ closer to the tail (smaller from_bottom).
    let upper = main_scrollbar_from_bottom_from_mouse(&app, 39, 2).expect("upper hit");
    let lower = main_scrollbar_from_bottom_from_mouse(&app, 39, 7).expect("lower hit");
    assert!(upper > lower, "click-to-jump is monotonic down the track");
    // A click outside the gutter column is not a scrollbar hit.
    assert!(main_scrollbar_from_bottom_from_mouse(&app, 0, 5).is_none());
}

#[test]
fn main_scrollbar_click_routes_through_handle_mouse() {
    // End-to-end: a left-click on the cached gutter actually moves the scroll
    // state via the production `handle_mouse` dispatch.
    let mut app = app_with_user_turns(200);
    // Populate the gutter cache by rendering the transcript once.
    let _ = render_transcript_to_string(&app, 40, 12);
    let cache = app
        .main_scrollbar_cache
        .get()
        .expect("overflow caches the gutter");
    let gutter_x = cache.scrollbar_area.x;
    let gutter_top_y = cache.scrollbar_area.y;
    assert!(app.transcript_scroll.is_following());
    let moved = handle_mouse(
        &mut app,
        crossterm::event::MouseEvent {
            kind: MouseEventKind::Down(crossterm::event::MouseButton::Left),
            column: gutter_x,
            row: gutter_top_y,
            modifiers: KeyModifiers::NONE,
        },
    );
    assert!(
        moved,
        "clicking the top of the gutter changes the scroll state"
    );
    assert!(
        app.transcript_scroll.from_bottom() > 0,
        "clicking the top of the gutter scrolls up off the tail",
    );
    assert!(!app.transcript_scroll.is_following());
}

// ---- resize anchoring (render-level) ------------------------------------

#[test]
fn resize_while_following_stays_at_latest() {
    // A following view shows the newest entry at every viewport height.
    let mut app = app_with_user_turns(199);
    app.push_transcript_item(TranscriptItem::user("LATEST_ENTRY".to_string()));
    assert!(app.transcript_scroll.is_following());
    for height in [8u16, 16, 24, 40] {
        let frame = render_transcript_to_string(&app, 40, height);
        assert!(
            frame.contains("LATEST_ENTRY"),
            "a following view shows the latest entry at height {height}:\n{frame}",
        );
    }
}

#[test]
fn resize_while_scrolled_up_keeps_same_logical_content_visible() {
    // Scroll up to a fixed logical anchor, then resize the viewport. Because the
    // scroll position is logical (`from_bottom`), the BOTTOM line of the viewport
    // is `total - 1 - from_bottom` regardless of viewport height, so the content
    // anchored at the bottom of the view is identical across resizes.
    let width = 40u16;
    let text_width = width - 1; // 1-cell scrollbar gutter.
    let mut app = app_with_user_turns(300);
    // True wrapped-row count at this text width (constant across height changes,
    // since only the height varies below). Pick an anchor safely mid-content.
    let total = transcript_lines_for_render(&app, Some(text_width), false).len();
    assert!(
        total > 80,
        "need plenty of rows to scroll within; got {total}"
    );
    let from_bottom = 30usize;
    // Use the SMALLEST height's geometry to store the anchor; smaller height =>
    // larger max_scroll, so this anchor is in range for every larger height too.
    let smallest = 10u16;
    app.transcript_scroll
        .set_from_bottom(from_bottom, total, smallest as usize);
    assert_eq!(app.transcript_scroll.from_bottom(), from_bottom);
    assert!(!app.transcript_scroll.is_following());

    // At the smallest height, capture the needle on the LAST content row — the
    // row anchored at `total - 1 - from_bottom`, which is height-independent.
    let small = render_transcript_to_string(&app, width, smallest);
    let needle = small
        .lines()
        .rev()
        .find_map(|line| {
            line.split_whitespace()
                .collect::<Vec<_>>()
                .windows(2)
                .find_map(|w| (w[0] == "turn").then(|| format!("turn {}", w[1])))
        })
        .expect("a 'turn N' needle is visible on screen");

    // Resize to larger heights without touching the scroll state. The same
    // bottom-anchored content must remain visible, and the view stays scrolled.
    for height in [16u16, 24, 30] {
        let frame = render_transcript_to_string(&app, width, height);
        assert!(
            frame.contains(&needle),
            "scrolled-up content {needle:?} must stay visible after resize to height {height}:\n{frame}",
        );
        assert!(
            !app.transcript_scroll.is_following(),
            "a resize must not silently re-pin a scrolled-up view",
        );
    }
}

#[test]
fn reanchor_on_resize_re_pins_following_and_clamps_scrolled_up() {
    // `reanchor_active_scroll_on_resize` is the production resize hook. A
    // following view re-pins; a scrolled-up view keeps a meaningful (clamped)
    // anchor. Geometry here resolves through the 80x24 fallback.
    let mut app = app_with_user_turns(200);
    // Following: stays pinned.
    reanchor_active_scroll_on_resize(&mut app, None);
    assert_eq!(app.transcript_scroll.from_bottom(), 0);
    assert!(app.transcript_scroll.is_following());
    // Scrolled up beyond what the (clamped) geometry allows: the reanchor caps
    // it to the real max_scroll rather than leaving it pointing past content.
    let (line_count, viewport_h) = active_transcript_geometry(&app);
    let max_scroll = line_count.saturating_sub(viewport_h);
    app.transcript_scroll = scroll::ScrollState::scrolled_up(max_scroll + 1_000);
    reanchor_active_scroll_on_resize(&mut app, None);
    assert_eq!(
        app.transcript_scroll.from_bottom(),
        max_scroll,
        "a resize clamps an over-scrolled anchor to the content top",
    );
    assert!(!app.transcript_scroll.is_following());
}

// ---- Focus-Preserving Resize (§12.4.3) ---------------------------------

/// Long, wrap-prone user prompts so a width change reflows each entry to a
/// different number of rows — the situation that makes a bare `from_bottom`
/// point at the wrong entry without the §12.4.3 re-anchor.
fn app_with_wrapping_turns(count: usize) -> TuiApp {
    let mut app = test_app(SessionMode::Build);
    app.set_test_frame_size(80, 24);
    for index in 0..count {
        app.push_transcript_item(TranscriptItem::user(format!(
            "turn {index}: a deliberately long prompt that wraps across several \
             rows at a narrow width so the resize reflow changes its height and \
             the scroll anchor must follow the entry, not the row count"
        )));
    }
    app
}

#[test]
fn resize_keeps_the_same_entry_anchored_across_a_wrap_reflow() {
    // The core §12.4.3 behavior: scroll up so a known entry sits at the top, then
    // a resize narrows the width (each entry now wraps to MORE rows). The same
    // entry must stay anchored at the top rather than the view jumping to a
    // different entry because the stale `from_bottom` indexes new geometry.
    let mut app = app_with_wrapping_turns(40);
    app.set_test_frame_size(80, 20);
    // Scroll up off the tail to a mid-transcript position.
    scroll_transcript_up(&mut app, 60);
    let anchored_before = current_top_entry_id(&app).expect("a top entry while scrolled up");
    assert!(
        !app.transcript_scroll.is_following(),
        "the view is scrolled up, not following the tail",
    );

    // Resize to a much narrower width: every entry reflows to more rows. Capture
    // runs against the still-current 80x20 (`off_frame`) geometry; the new size
    // is passed in just as the `Event::Resize` arm does, so the re-pin measures
    // the 40-wide geometry. The next painted frame is 40 wide too.
    reanchor_active_scroll_on_resize(&mut app, Some((40, 20)));
    app.set_test_frame_size(40, 20);

    let anchored_after = current_top_entry_id(&app).expect("a top entry after the reflow");
    assert_eq!(
        anchored_after, anchored_before,
        "the same logical entry stays at the top across the wrap reflow",
    );
}

#[test]
fn resize_keeps_a_following_view_pinned_to_the_tail() {
    // A live (tail-following) view must stay pinned to the tail across a resize —
    // the anchor logic never freezes a live view onto a stale entry.
    let mut app = app_with_wrapping_turns(30);
    assert!(app.transcript_scroll.is_following());
    reanchor_active_scroll_on_resize(&mut app, Some((48, 18)));
    assert!(
        app.transcript_scroll.is_following(),
        "a following view re-pins to the tail, not to a captured anchor",
    );
    assert_eq!(app.transcript_scroll.from_bottom(), 0);
}

#[test]
fn resize_clamps_a_dangling_focus_index_to_a_visible_row() {
    // A focus index left past the end of a transcript that shrank (a prune
    // between a resize-storm burst) must clamp to a visible row, never dangle.
    let mut app = app_with_user_turns(10);
    app.selected_entry = Some(9);
    app.transcript.truncate(4); // the focused row no longer exists

    reanchor_active_scroll_on_resize(&mut app, None);

    let index = app
        .selected_entry
        .expect("a non-empty transcript keeps a visible focus");
    assert!(
        index < app.transcript.len(),
        "focus clamps to a valid, visible row, not a dangling index",
    );
    assert_eq!(index, 3, "clamps to the new last row");
}

#[test]
fn resize_on_empty_transcript_clears_focus() {
    // Every entry vanished under the resize: there is no row to fall back to, so
    // focus clears rather than dangling at a phantom index.
    let mut app = app_with_user_turns(3);
    app.selected_entry = Some(1);
    app.transcript.clear();

    reanchor_active_scroll_on_resize(&mut app, None);

    assert_eq!(
        app.selected_entry, None,
        "no visible row remains, so focus clears",
    );
}

#[test]
fn resize_leaves_unfocused_view_unfocused() {
    // A resize must never conjure a selection out of an unfocused transcript.
    let mut app = app_with_user_turns(8);
    assert_eq!(app.selected_entry, None, "starts unfocused");
    reanchor_active_scroll_on_resize(&mut app, None);
    assert_eq!(app.selected_entry, None, "still unfocused after resize");
}

#[test]
fn resize_does_not_touch_main_focus_while_subagent_active() {
    // The subagent view has no main-view focus; a resize while it is active must
    // leave the main transcript's `selected_entry` exactly as the user left it
    // (so returning to main restores the same focused entry).
    let mut app = app_with_two_subagents();
    for index in 0..6 {
        app.push_transcript_item(TranscriptItem::user(format!("main turn {index}")));
    }
    app.selected_entry = Some(2);
    app.subagent_pane.active = ConversationSource::Subagent(1);

    reanchor_active_scroll_on_resize(&mut app, None);

    assert_eq!(
        app.selected_entry,
        Some(2),
        "main focus is untouched while a subagent conversation is active",
    );
}

#[tokio::test]
async fn resize_storm_through_dispatch_keeps_anchor_stable() {
    // Drive the feature through the REAL input path: a burst of `Event::Resize`
    // events (a window-drag storm) flows through `dispatch_input_events`, which
    // runs the production `reanchor_active_scroll_on_resize` hook. Scrolled up,
    // the same logical entry stays anchored at the top across the whole storm of
    // different widths.
    let mut app = app_with_wrapping_turns(50);
    let mut agent = test_agent(SessionMode::Build);
    app.set_test_frame_size(80, 20);
    scroll_transcript_up(&mut app, 80);
    let anchored = current_top_entry_id(&app).expect("a top entry while scrolled up");

    for (w, h) in [(60_u16, 24_u16), (40, 30), (100, 16), (52, 22)] {
        dispatch_input_events(&mut app, &mut agent, vec![Event::Resize(w, h)])
            .await
            .expect("dispatch resize");
        // The painted size is what the next off-frame geometry measures against.
        app.set_test_frame_size(w, h);
        assert_eq!(
            current_top_entry_id(&app),
            Some(anchored),
            "the anchored entry survives every resize in the storm ({w}x{h})",
        );
    }
}

#[tokio::test]
async fn resize_keeps_anchored_entry_painted_after_reflow() {
    // The "resize where the feature paints" case: scrolled up onto a known entry,
    // a resize fires through the real input path, then the production `render()`
    // is driven via a `TestBackend`. The anchored entry's content is still on
    // screen after the reflow (the feature did not strand the user's anchor
    // off-view).
    let mut app = app_with_wrapping_turns(40);
    let mut agent = test_agent(SessionMode::Build);
    app.set_test_frame_size(72, 20);
    scroll_transcript_up(&mut app, 50);
    let anchored = current_top_entry_id(&app).expect("a top entry while scrolled up");
    let anchored_index = app
        .transcript
        .iter()
        .position(|entry| entry.id == anchored)
        .expect("anchored id is live");

    dispatch_input_events(&mut app, &mut agent, vec![Event::Resize(50, 20)])
        .await
        .expect("dispatch resize");
    app.set_test_frame_size(50, 20);

    assert_eq!(
        current_top_entry_id(&app),
        Some(anchored),
        "the same entry is anchored at the top after the reflow",
    );
    // The real renderer paints the anchored region — the anchored entry (or its
    // immediate neighbour at the top boundary) is on screen — and the view did
    // NOT jump to the tail: the last turn is nowhere near the top of the frame.
    let frame = render_to_string(&app, 50, 20);
    let anchor_region_painted = frame.contains(&format!("turn {anchored_index}:"))
        || frame.contains(&format!("turn {}:", anchored_index + 1));
    assert!(
        anchor_region_painted,
        "the anchored entry's region is painted after the resize:\n{frame}",
    );
    let last_turn = app.transcript.len() - 1;
    assert!(
        !frame.contains(&format!("turn {last_turn}:")),
        "the view stayed anchored mid-transcript, it did not jump to the tail:\n{frame}",
    );
    assert!(
        !app.transcript_scroll.is_following(),
        "the resize kept the scrolled-up anchor, it did not re-pin to the tail",
    );
}

// ---- scrolled-vs-live indicator ----------------------------------------

#[test]
fn scrolled_indicator_appears_only_when_scrolled_up() {
    let mut app = app_with_user_turns(120);
    // Following: no "from live" badge.
    let live = render_transcript_to_string(&app, 60, 12);
    assert!(
        !live.contains("from live"),
        "a following view shows no scrolled indicator:\n{live}",
    );
    // Scroll up: the badge appears and reports the EXACT live distance. The
    // count is the load-bearing value, so derive it the way the renderer does
    // (`offset_from_bottom` against the real render geometry) rather than echoing
    // the raw `set_from_bottom` arg — the stored value clamps to `max_scroll`, so
    // a hard-coded 20 can disagree with what is painted.
    let render_w: u16 = 60;
    let render_h: u16 = 12;
    app.transcript_scroll.set_from_bottom(20, 320, 12);
    // Reproduce the render geometry: `render_transcript` carves the optional
    // minimap rail and the 1-cell scrollbar gutter off the right edge (height is
    // untouched), and `include_startup_card` is gated on `area.height >= 16`.
    let area = Rect::new(0, 0, render_w, render_h);
    let (body_area, _rail) = transcript_main_body_and_rail_areas(area, app.show_minimap);
    let (text_area, _scrollbar) = transcript_main_text_and_scrollbar_areas(body_area);
    let include_startup_card = area.height >= 16;
    let total_rows =
        transcript_lines_for_render(&app, Some(text_area.width), include_startup_card).len();
    let viewport_h = text_area.height as usize;
    let expected_from_bottom = app
        .transcript_scroll
        .offset_from_bottom(total_rows, viewport_h);
    assert!(
        expected_from_bottom > 0,
        "the test geometry must leave the view scrolled up (got {expected_from_bottom})",
    );
    let scrolled = render_transcript_to_string(&app, render_w, render_h);
    let expected_badge = format!("↑ {expected_from_bottom} from live");
    assert!(
        scrolled.contains(&expected_badge),
        "a scrolled-up view shows the exact live distance {expected_badge:?}:\n{scrolled}",
    );
    // Cross-check by parsing the painted count back out of the badge: it must
    // equal the renderer-derived offset, not the raw `set_from_bottom` arg.
    let painted = scrolled
        .split('↑')
        .nth(1)
        .and_then(|rest| rest.split_whitespace().next())
        .and_then(|n| n.parse::<usize>().ok())
        .expect("the badge carries a parseable '↑ N' count");
    assert_eq!(
        painted, expected_from_bottom,
        "the painted live distance matches `offset_from_bottom`:\n{scrolled}",
    );
}

#[test]
fn transcript_scroll_offset_defaults_to_bottom() {
    // `scroll_offset_for_from_bottom(from_bottom, total_rows, viewport_h)` =
    // total_rows - viewport_h - from_bottom, saturating.
    assert_eq!(scroll_offset_for_from_bottom(0, 20, 10), 10);
    assert_eq!(scroll_offset_for_from_bottom(8, 20, 10), 2);
    assert_eq!(scroll_offset_for_from_bottom(usize::MAX, 20, 10), 0);
}

