#[test]
fn osc52_clipboard_rejects_payloads_above_cap() {
    let mut clipboard = Osc52Clipboard;
    let oversized = "x".repeat(OSC52_MAX_PAYLOAD_BYTES + 1);
    let err = clipboard
        .copy_text(&oversized)
        .expect_err("oversized payload must fail");
    assert!(err.contains("exceeds"), "{err}");
    assert!(err.contains(&OSC52_MAX_PAYLOAD_BYTES.to_string()), "{err}");
}

/// Finding 1 (Phase 5a review): the app-layer copy path must be able to inject
/// a recording sink so a copy that falls through to the richer
/// `ClipboardChain` lands the exact bytes on a TEST seam — never real OSC 52 /
/// subprocess / temp-file I/O. Drives the production `deliver_copy` with the
/// primary sink failing and an oversized payload (so the chain is consulted),
/// and asserts the chain delivered our payload to the injected
/// `RecordingSink`.
#[test]
fn deliver_copy_routes_oversized_payload_to_injected_recording_sink() {
    // Primary clipboard fails so `deliver_copy` falls through to the chain.
    let mut app = test_app_with_clipboard(
        SessionMode::Build,
        Box::new(RecordingClipboard {
            writes: Arc::new(StdMutex::new(Vec::new())),
            error: Some("primary sink unavailable".to_string()),
        }),
    );

    // Inject a recording sink into the semantic-copy chain; retain a shared
    // handle so we can read back exactly what reached it.
    let sink = crate::clipboard::RecordingSink::new();
    let calls = sink.handle();
    app.set_clipboard_sink_for_test(Box::new(sink));

    // Oversized so `deliver_copy` consults the chain (small copies stay on the
    // primary OSC 52 path and never touch the chain).
    let payload = "z".repeat(OSC52_MAX_PAYLOAD_BYTES + 1);
    deliver_copy(&mut app, &payload, "assistant message");

    // The chain reported success (a provider accepted it) and the recorded
    // bytes carry our exact payload — proving the copy reached the test seam,
    // not a real terminal/clipboard/subprocess.
    assert!(
        app.status.starts_with("copied assistant message"),
        "expected a copied-status, got {:?}",
        app.status
    );
    let recorded = calls.lock().unwrap().clone();
    assert!(!recorded.is_empty(), "the chain must have used the sink");
    let landed = recorded.iter().any(|call| match call {
        // The payload is oversized for OSC 52's cap, so a platform command
        // carries the raw bytes verbatim.
        crate::clipboard::SinkCall::Command { payload: p, .. } => p == payload.as_bytes(),
        // If the env-probed chain has no OSC 52 and a platform command, the
        // temp-file fallback still carries the exact bytes.
        crate::clipboard::SinkCall::TempFile { payload: p, .. } => p == payload.as_bytes(),
        // OSC 52 only ever sees the base64 escape, never the raw payload.
        crate::clipboard::SinkCall::Terminal { .. } => false,
    });
    assert!(
        landed,
        "the exact payload bytes must reach the injected sink, calls: {recorded:?}"
    );
}

// ===========================================================================
// Zen Mode (§12.4.5)
// ===========================================================================

/// `Ctrl+Alt+.` resolves to `ToggleZenMode`.
fn toggle_zen_key() -> KeyEvent {
    KeyEvent::new(
        KeyCode::Char('.'),
        KeyModifiers::CONTROL | KeyModifiers::ALT,
    )
}

/// A test app seeded with transcript content and the secondary chrome (minimap
/// rail + breadcrumbs strip) turned on, so a render shows the chrome zen hides.
fn zen_test_app() -> TuiApp {
    let mut app = test_app(SessionMode::Build);
    app.push_log("hello transcript world".to_string());
    app.show_minimap = true;
    app.breadcrumbs_open = true;
    app
}

#[tokio::test]
async fn zen_keyboard_toggle_hides_chrome_but_keeps_transcript() {
    let mut agent = test_agent(SessionMode::Build);
    let mut app = zen_test_app();

    // Before zen: the breadcrumbs strip paints its `session ▸ …` trail and the
    // detailed status block is up; the transcript content is visible.
    let before = render_to_string(&app, 120, 24);
    assert!(before.contains("hello transcript world"), "{before}");
    assert!(
        before.contains('\u{25b8}'),
        "breadcrumbs strip paints its ▸ trail before zen: {before}"
    );
    assert!(
        !before.contains("click to exit"),
        "the zen exit hint is absent before zen: {before}"
    );

    // Toggle zen on through the real key dispatcher.
    handle_key(&mut app, &mut agent, toggle_zen_key())
        .await
        .unwrap();
    assert!(app.zen.is_active(), "Ctrl+Alt+. turned zen on");

    let after = render_to_string(&app, 120, 24);
    // The transcript and composer survive — zen is layout policy, not a content
    // filter.
    assert!(
        after.contains("hello transcript world"),
        "transcript stays visible in zen: {after}"
    );
    // The minimal one-line state replaces the detailed status block, and names the
    // way out so the exit is always on screen.
    assert!(
        after.contains("click to exit"),
        "zen paints its minimal exit line: {after}"
    );
    // Secondary chrome is gone: the breadcrumbs strip no longer paints its trail.
    assert!(
        !after.contains('\u{25b8}'),
        "breadcrumbs strip is suppressed in zen: {after}"
    );
    // And it registers no click target — a precise assertion that the suppressed
    // strip is non-interactive (not just visually absent from the global frame).
    assert!(
        app.registered_rect_for(interaction::TargetKey::Chrome(
            interaction::ChromeKey::BreadcrumbCrumb(0),
        ))
        .is_none(),
        "the suppressed breadcrumb strip registers no click target in zen",
    );

    // Toggling again restores the chrome (idempotent round-trip).
    handle_key(&mut app, &mut agent, toggle_zen_key())
        .await
        .unwrap();
    assert!(!app.zen.is_active(), "second Ctrl+Alt+. turned zen off");
    let restored = render_to_string(&app, 120, 24);
    assert!(
        restored.contains('\u{25b8}'),
        "breadcrumbs strip returns when zen is off: {restored}"
    );
    assert!(
        !restored.contains("click to exit"),
        "the zen exit hint is gone when zen is off: {restored}"
    );
}

#[test]
fn zen_minimal_status_line_click_exits_zen() {
    let mut app = zen_test_app();
    // Enter zen, then paint so the minimal status line registers its click target.
    app.zen.toggle();
    assert!(app.zen.is_active());
    let _ = render_to_string(&app, 120, 24);
    let rect = app
        .registered_rect_for(interaction::TargetKey::Chrome(
            interaction::ChromeKey::ZenStatusLine,
        ))
        .expect("the zen minimal status line registered a click target");

    // A left-click anywhere on the line is the mouse twin of Ctrl+Alt+.: it leaves
    // zen, driving the same handler.
    handle_mouse(
        &mut app,
        crossterm::event::MouseEvent {
            kind: MouseEventKind::Down(crossterm::event::MouseButton::Left),
            column: rect.x + 1,
            row: rect.y,
            modifiers: KeyModifiers::NONE,
        },
    );
    assert!(
        !app.zen.is_active(),
        "clicking the minimal zen status line exits zen",
    );
}

#[test]
fn zen_renders_on_empty_transcript_and_tiny_terminal_without_panicking() {
    // Edge case: an empty transcript in zen on a terminal too small for most
    // chrome must still paint a frame (the minimal status line clips, never
    // panics).
    let mut app = test_app(SessionMode::Build);
    app.zen.toggle();
    assert!(app.transcript.is_empty());
    for (w, h) in [(3u16, 2u16), (1, 1), (20, 4)] {
        let _ = render_to_string(&app, w, h);
    }
    // A roomier empty-transcript zen frame still names the way out.
    let output = render_to_string(&app, 80, 12);
    assert!(
        output.contains("click to exit"),
        "empty-transcript zen still paints the exit line: {output}"
    );
}

#[test]
fn zen_survives_resize_where_the_minimal_status_paints() {
    // The minimal status line must keep painting (and re-registering its click
    // target) across a width/height change — the spec's "resize while in zen".
    let mut app = zen_test_app();
    app.zen.toggle();
    for (w, h) in [(120u16, 24u16), (60, 40), (200, 10)] {
        let output = render_to_string(&app, w, h);
        assert!(
            output.contains("click to exit"),
            "zen exit line survives resize to {w}x{h}: {output}"
        );
        assert!(
            app.registered_rect_for(interaction::TargetKey::Chrome(
                interaction::ChromeKey::ZenStatusLine,
            ))
            .is_some(),
            "the zen click target re-registers after resize to {w}x{h}",
        );
        // The transcript content keeps painting through every reflow.
        assert!(
            output.contains("hello transcript world"),
            "transcript survives resize to {w}x{h}: {output}"
        );
    }
}

/// Pin the user-scope settings to a scratch file so the Zen persistence
/// round-trip is isolated, returning the guard plus the scratch path. Mirrors
/// `glyph_mode_scratch` / the density on-disk pattern.
fn zen_scratch(app: &mut TuiApp, name: &str) -> (ScopedSettingsPath, PathBuf) {
    let dir = temp_workspace(name);
    let settings_path = dir.join("settings.toml");
    let guard = ScopedSettingsPath::new(settings_path.clone());
    app.set_settings_path_override(Some(settings_path.clone()));
    (guard, settings_path)
}

#[tokio::test]
async fn zen_toggle_persists_true_then_clears_the_key_on_exit() {
    // The material on-disk paths: toggling zen ON writes `[tui] zen = true`;
    // toggling it OFF clears the key entirely via `EditOp::Unset` (never `false`),
    // so a never-zen-again session leaves no stale `true` behind.
    let mut agent = test_agent(SessionMode::Build);
    let mut app = test_app(SessionMode::Build);
    let (_guard, settings_path) = zen_scratch(&mut app, "zen_persist_toggle");

    handle_key(&mut app, &mut agent, toggle_zen_key())
        .await
        .unwrap();
    assert!(app.zen.is_active(), "zen turned on");
    let written = std::fs::read_to_string(&settings_path).expect("settings written on zen-on");
    let table = written.parse::<toml::Table>().expect("valid TOML");
    assert_eq!(
        table
            .get("tui")
            .and_then(|t| t.as_table())
            .and_then(|t| t.get("zen"))
            .and_then(|v| v.as_bool()),
        Some(true),
        "zen-on persisted `[tui] zen = true`: {written}"
    );

    // Toggle off: the key is CLEARED, not written as `false`.
    handle_key(&mut app, &mut agent, toggle_zen_key())
        .await
        .unwrap();
    assert!(!app.zen.is_active(), "zen turned off");
    let cleared = std::fs::read_to_string(&settings_path).unwrap_or_default();
    let cleared_zen = cleared
        .parse::<toml::Table>()
        .ok()
        .and_then(|t| t.get("tui").and_then(|x| x.as_table()).cloned())
        .and_then(|t| t.get("zen").cloned());
    assert!(
        cleared_zen.is_none(),
        "zen-off cleared the key (no stale `zen = ...` left): {cleared}"
    );
}

#[tokio::test]
async fn zen_restore_reads_a_persisted_true_and_ignores_malformed_values() {
    // `restore_zen` reads `[tui].zen` as a bool at startup. A real `true` restores
    // zen; a non-bool / unset value (`"yes"`, `1`, missing) collapses to the
    // chrome-on default rather than panicking.
    let mut app = test_app(SessionMode::Build);
    let (_guard, settings_path) = zen_scratch(&mut app, "zen_persist_restore");

    std::fs::write(&settings_path, "[tui]\nzen = true\n").unwrap();
    restore_zen(&mut app);
    assert!(
        app.zen.is_active(),
        "a persisted `zen = true` restores zen at startup"
    );

    for bad in [
        "[tui]\nzen = \"yes\"\n",
        "[tui]\nzen = 1\n",
        "[other]\nk = 1\n",
    ] {
        std::fs::write(&settings_path, bad).unwrap();
        let mut fresh = test_app(SessionMode::Build);
        fresh.set_settings_path_override(Some(settings_path.clone()));
        restore_zen(&mut fresh);
        assert!(
            !fresh.zen.is_active(),
            "a malformed / non-bool / missing zen value yields the default (off): {bad:?}"
        );
    }
}

#[tokio::test]
async fn zen_persist_failure_notes_status_but_keeps_the_latch() {
    // Best-effort persistence: if the settings file cannot be written, the toggle
    // still flips the in-session latch and the status reports the save failure.
    // Point the settings "file" at a DIRECTORY so the write fails deterministically.
    let mut agent = test_agent(SessionMode::Build);
    let mut app = test_app(SessionMode::Build);
    let dir = temp_workspace("zen_persist_failure");
    let unwritable = dir.join("settings-is-a-dir.toml");
    std::fs::create_dir_all(&unwritable).expect("create the blocking directory");
    let _guard = ScopedSettingsPath::new(unwritable.clone());
    app.set_settings_path_override(Some(unwritable));

    handle_key(&mut app, &mut agent, toggle_zen_key())
        .await
        .unwrap();
    assert!(
        app.zen.is_active(),
        "the in-session zen latch still flips even when the save fails"
    );
    assert!(
        app.status.contains("save failed"),
        "the status reports the persist failure: {}",
        app.status
    );
}

#[test]
fn zen_registers_status_and_click_target_at_the_smallest_nondegenerate_size() {
    // The tiny-terminal boundary: at the smallest size that still has a status row,
    // zen must paint its minimal status line AND register the click target (not just
    // avoid a panic).
    let mut app = zen_test_app();
    app.zen.toggle();
    assert!(app.zen.is_active());
    // 20x4 is the smallest non-degenerate frame the existing no-panic test
    // exercises. The full "… click to exit" cue clips at this width, but the line's
    // leading "zen" mode marker survives, and — load-bearing — the whole line still
    // registers its click target so the mouse exit stays reachable.
    let output = render_to_string(&app, 20, 4);
    assert!(
        output.contains("zen"),
        "the minimal zen status line paints (its leading marker survives) at 20x4: {output}"
    );
    assert!(
        app.registered_rect_for(interaction::TargetKey::Chrome(
            interaction::ChromeKey::ZenStatusLine,
        ))
        .is_some(),
        "the zen status line registers a click target even at the smallest size",
    );
}

