#[tokio::test]
async fn right_click_on_queue_row_runs_it_next_via_mouse() {
    // Mouse parity: a right-click on a queued row drives the same run-next verb
    // the keyboard `r` does, through the real render() hit-test registry. Idle,
    // so it promotes to the front and arms the drain.
    let mut app = queue_app(&["aaa", "bbb", "ccc"]);
    let width = 100u16;
    let height = 20u16;
    let _ = render_to_string(&app, width, height);

    let id_ccc = queue_id_at(&app, 2);
    // Any registered QueueItem cell for "ccc" works — right-click hit-tests the
    // row by its QueueItem key regardless of which left-click action owns the
    // cell, so target on the reorder handle (the row body).
    let (col, row) = queue_cell_for(
        &app,
        width,
        height,
        interaction::TargetKey::QueueItem(id_ccc),
        interaction::Action::QueueReorderBegin(id_ccc),
    )
    .expect("ccc row registered");

    handle_mouse(
        &mut app,
        crossterm::event::MouseEvent {
            kind: MouseEventKind::Down(crossterm::event::MouseButton::Right),
            column: col,
            row,
            modifiers: KeyModifiers::NONE,
        },
    );

    assert_eq!(queue_texts(&app), vec!["ccc", "aaa", "bbb"]);
    assert_eq!(queue_id_at(&app, 0), id_ccc);
    assert!(
        app.auto_drain_queue,
        "idle right-click run-next arms the drain"
    );
    assert!(app.prompt_queue_overlay.is_none());
}

#[test]
fn queue_overlay_paints_the_run_next_hint_across_a_resize() {
    // The overlay header advertises the new `r run next` verb; it must paint at
    // both a wide and a narrow terminal (the feature paints into the footer).
    let mut app = queue_app(&["draft one", "draft two"]);
    if let Some(state) = app.prompt_queue_overlay.as_mut() {
        state.selected = 0;
    }
    for (w, h) in [(120u16, 16u16), (60u16, 16u16)] {
        let rendered = render_to_string(&app, w, h);
        assert!(
            rendered.contains("run next"),
            "run-next affordance must be visible at {w}x{h}: {rendered}"
        );
    }
}

#[tokio::test]
async fn ctrl_click_toggles_multiselect_via_mouse() {
    // Render so the per-item hit targets register, then Ctrl-click "beta".
    let mut app = queue_app(&["alpha", "beta", "gamma"]);
    let width = 100u16;
    let height = 20u16;
    let _ = render_to_string(&app, width, height);
    let id_beta = queue_id_at(&app, 1);
    let cell = {
        let registry = app.clickables.borrow();
        let mut found = None;
        'outer: for y in 0..height {
            for x in 0..width {
                if let Some((key, _)) = registry.hit_test(x, y)
                    && key == interaction::TargetKey::QueueItem(id_beta)
                {
                    found = Some((x, y));
                    break 'outer;
                }
            }
        }
        found
    };
    let (col, row) = cell.expect("beta hit target registered");
    handle_mouse(
        &mut app,
        crossterm::event::MouseEvent {
            kind: MouseEventKind::Down(crossterm::event::MouseButton::Left),
            column: col,
            row,
            modifiers: KeyModifiers::CONTROL,
        },
    );
    // The Ctrl-click tags beta (and seats the focus there) WITHOUT deleting or
    // reordering it — the queue is untouched.
    assert!(app.prompt_queue_multiselect.contains(id_beta));
    assert_eq!(queue_texts(&app), vec!["alpha", "beta", "gamma"]);
    assert!(app.prompt_queue_drag.is_none(), "tag must not arm a drag");
}

#[tokio::test]
async fn keyboard_and_mouse_tag_reach_the_same_group() {
    // Keyboard Space on index 1 and Ctrl-click on index 1 must produce the
    // identical group membership — keyboard/mouse parity.
    let (kb, _a) = queue_app_with_tags(&["a", "b", "c"], &[1]).await;
    let kb_id = queue_id_at(&kb, 1);

    let mut ms = queue_app(&["a", "b", "c"]);
    let _ = render_to_string(&ms, 100, 20);
    let id1 = queue_id_at(&ms, 1);
    queue_toggle_id_multiselect(&mut ms, id1);

    assert!(kb.prompt_queue_multiselect.contains(kb_id));
    assert!(ms.prompt_queue_multiselect.contains(id1));
    assert_eq!(
        kb.prompt_queue_multiselect.len(),
        ms.prompt_queue_multiselect.len()
    );
}

#[tokio::test]
async fn render_shows_checkbox_for_tagged_rows_and_survives_resize() {
    let (app, _agent) = queue_app_with_tags(&["alpha", "beta", "gamma"], &[1]).await;
    // Wide layout: the tagged row paints a filled checkbox, the others empty.
    let wide = render_to_string(&app, 120, 24);
    assert!(wide.contains("[x]"), "tagged row checkbox missing:\n{wide}");
    assert!(
        wide.contains("[ ]"),
        "untagged row checkbox missing:\n{wide}"
    );
    // Re-rendering at a narrow width must not panic and still paints the
    // overlay rows (rects recompute from the live geometry).
    let narrow = render_to_string(&app, 48, 24);
    assert!(
        narrow.contains("[x]"),
        "checkbox lost after resize:\n{narrow}"
    );
}

#[tokio::test]
async fn closing_overlay_clears_the_multiselect_group() {
    let (mut app, mut agent) = queue_app_with_tags(&["a", "b"], &[0, 1]).await;
    assert_eq!(app.prompt_queue_multiselect.len(), 2);
    // Esc closes the overlay (Enter now opens the focused prompt for editing,
    // §11G.8); the group must not survive into the next open.
    handle_key(
        &mut app,
        &mut agent,
        KeyEvent::new(KeyCode::Esc, KeyModifiers::NONE),
    )
    .await
    .expect("close overlay");
    assert!(app.prompt_queue_overlay.is_none());
    assert!(app.prompt_queue_multiselect.is_empty());
}

#[test]
fn sync_queue_ids_heals_front_drain() {
    // Simulate an external front-drain (a queued prompt ran) without touching
    // the id sidecar, then verify sync re-aligns to the surviving tail.
    let mut app = queue_app(&["a", "b", "c"]);
    let id_b = queue_id_at(&app, 1);
    let id_c = queue_id_at(&app, 2);
    app.prompt_queue.pop_front(); // drop "a"
    sync_queue_ids(&mut app);
    assert_eq!(app.prompt_queue_ids.len(), 2);
    assert_eq!(
        app.prompt_queue_ids.iter().copied().collect::<Vec<_>>(),
        vec![id_b, id_c]
    );
}

#[test]
fn sync_queue_ids_heals_back_enqueue() {
    // Simulate an external back-enqueue without stamping an id.
    let mut app = queue_app(&["a", "b"]);
    app.prompt_queue.push_back("c".to_string());
    sync_queue_ids(&mut app);
    assert_eq!(app.prompt_queue_ids.len(), 3);
    // The new tail got a fresh, unique id.
    let ids: Vec<u64> = app.prompt_queue_ids.iter().copied().collect();
    assert_eq!(ids[0..2], [0, 1]);
    assert_eq!(ids[2], 2);
}

// ---------------------------------------------------------------------------
// Phase 8: main transcript render cache — integration tests.
//
// These drive the real `transcript_lines_and_entry_offsets` path through a
// `TuiApp` (the unit tests for the cache primitives live in
// `main_render_cache_tests.rs`). They prove: the assembled cache hits on an
// unchanged second frame; it invalidates on every key dimension; the painted
// output is byte-for-byte identical with and without the cache; and selection /
// search highlight (a post-pass, deliberately NOT keyed) still changes the
// painted output while keeping the underlying row cache warm.
// ---------------------------------------------------------------------------

/// One span's full visual fingerprint: text + fg + bg + set/cleared modifiers.
type SpanFingerprint = (String, Option<Color>, Option<Color>, u16, u16);

/// A fingerprint of one wrapped line that captures text AND every styling
/// attribute, so "byte-for-byte identical" comparisons catch a style drift the
/// plain-text projection would miss.
fn line_fingerprint(line: &Line<'static>) -> Vec<SpanFingerprint> {
    line.spans
        .iter()
        .map(|s| {
            (
                s.content.to_string(),
                s.style.fg,
                s.style.bg,
                s.style.add_modifier.bits(),
                s.style.sub_modifier.bits(),
            )
        })
        .collect()
}

fn rows_fingerprint(rows: &[Line<'static>]) -> Vec<Vec<SpanFingerprint>> {
    rows.iter().map(line_fingerprint).collect()
}

fn main_render_app() -> TuiApp {
    let mut app = test_app(SessionMode::Build);
    app.push_transcript_item(TranscriptItem::user(
        "explain the architecture of this module in detail please",
    ));
    app.push_transcript_item(TranscriptItem::assistant(
        "The module is split into a builder and a wrapper. The builder assembles \
         logical lines for every transcript entry and then wraps them to visual \
         rows; the wrapper memoises that result behind a revision-keyed LRU so an \
         idle frame reuses the rows instead of rebuilding them.",
    ));
    app.push_transcript_item(TranscriptItem::user("and what about caching?"));
    app.push_transcript_item(TranscriptItem::assistant(
        "Caching keys on the entry revision, wrap width, detail policy, and theme.",
    ));
    app
}

/// Clear every entry's settle-fold so the assembled-render cache is exercised
/// rather than bypassed. The settle-fold bypass deliberately routes around the
/// cache (see `transcript_lines_and_entry_offsets`), so a freshly-pushed
/// reasoning/plan/tool entry would otherwise make a cached-vs-uncached test
/// trivially pass via the bypass instead of through the cache.
fn clear_all_settles(app: &mut TuiApp) {
    for entry in &mut app.transcript {
        entry.settle = None;
    }
}

/// A richer NON-subagent fixture that exercises the segmentation loop's
/// edge branches the plain `main_render_app` never hits: a render-time
/// coalesced tool run (its non-lead members take the suppressed `continue`),
/// a suppressed reasoning pair (the second reasoning entry takes its own
/// suppressed `continue`), and a non-empty pending-assistant tail painted with
/// the live moon span. Coalescing is forced on so the run actually folds.
fn main_render_app_rich() -> TuiApp {
    let mut app = test_app(SessionMode::Build);
    app.coalesce_tool_runs = true;
    app.show_reasoning_usage = true;
    app.push_transcript_item(TranscriptItem::user(
        "search the tree and summarise the matches",
    ));
    // Two adjacent reasoning entries -> lead + one suppressed member.
    app.push_reasoning_segment(squeezy_core::ReasoningSnapshot::from_payload(
        squeezy_core::ReasoningPayload::OpenAi {
            item_id: "rsn-rich-1".to_string(),
            summary: vec!["Plan: grep the tree, then read the hottest hits.".to_string()],
            encrypted_content: None,
        },
    ));
    app.push_reasoning_segment(squeezy_core::ReasoningSnapshot::from_payload(
        squeezy_core::ReasoningPayload::OpenAi {
            item_id: "rsn-rich-2".to_string(),
            summary: vec!["Refine: prioritise src/ over tests/.".to_string()],
            encrypted_content: None,
        },
    ));
    // Three adjacent same-tool same-status results -> a render-time coalesced
    // run (lead + two suppressed members).
    app.push_tool_result(sample_tool_result("grep", "src/a.rs:1: fn one("));
    app.push_tool_result(sample_tool_result("grep", "src/b.rs:2: fn two("));
    app.push_tool_result(sample_tool_result("grep", "src/c.rs:3: fn three("));
    app.push_transcript_item(TranscriptItem::assistant(
        "Found three matches across the source tree; the hottest is src/a.rs.",
    ));
    // A live pending-assistant tail (the trailing moon span + text) on a
    // Running turn, so `pending_assistant_display_content` is `Some` and the
    // tail's tick-pulsed moon is painted.
    app.pending_assistant
        .push_delta("Streaming the next part of the answer");
    app.turn_visual = TurnVisualState::Running;
    clear_all_settles(&mut app);
    app
}

/// A subagent-view fixture so the conversation-title head-chrome branch of the
/// segmentation loop (the `active_conversation_title` path, mutually exclusive
/// with the pending tail) is covered by the cached-vs-uncached sweep.
fn main_render_app_subagent() -> TuiApp {
    let mut app = test_app(SessionMode::Build);
    app.note_subagent_started(
        7,
        "delegate".to_string(),
        "Audit the auth module".to_string(),
    );
    app.subagent_pane.active = ConversationSource::Subagent(7);
    app.note_subagent_activity(
        7,
        "delegate".to_string(),
        "read src/auth.rs and flagged a weak hash".to_string(),
    );
    clear_all_settles(&mut app);
    app
}

// Hit/miss is asserted via `contains_main_key` (presence of this app's exact
// key in the process-wide LRU), which is race-free because every `TuiApp` mints
// a private `render_cache_session`. The global hit/miss stat counters are NOT
// used for exact assertions here — they race under parallel `cargo test`.
//
// Two shared resources make these tests order-sensitive:
//   1. The process-wide assembled-render LRU is small (cap 24); a concurrent
//      flood from another test could evict the slot we just warmed.
//   2. The render-cache KEY folds the process-global theme generation; a
//      sibling test that bumps it (`..._invalidates_on_theme_change`) could
//      change our key between computing it and rendering.
// So every test here holds BOTH the crate-shared cache lock (acquired first)
// and the existing `THEME_TEST_LOCK` (acquired second). The fixed order — cache
// before theme — matches the unit tests (which take only the cache lock) and
// cannot deadlock.
struct MainRenderTestGuard {
    _cache: std::sync::MutexGuard<'static, ()>,
    _theme: std::sync::MutexGuard<'static, ()>,
}

fn lock_main_render_theme() -> MainRenderTestGuard {
    let cache = crate::main_render_cache::test_lock();
    let theme = THEME_TEST_LOCK
        .lock()
        .unwrap_or_else(|poison| poison.into_inner());
    MainRenderTestGuard {
        _cache: cache,
        _theme: theme,
    }
}

#[test]
fn main_render_cache_hits_on_unchanged_second_frame() {
    let _theme = lock_main_render_theme();
    let app = main_render_app();
    let width = 60u16;
    let key = main_render_key(&app, width, false);
    assert!(
        !main_render_cache::contains_main_key(&key),
        "fresh app's key is not yet cached"
    );

    let first = transcript_lines_and_entry_offsets(&app, Some(width), false);
    assert!(
        main_render_cache::contains_main_key(&key),
        "first frame populated the cache for this key"
    );

    // The unchanged second frame serves the same key from the cache: the rows
    // and offsets are byte-for-byte identical to the first frame's.
    let second = transcript_lines_and_entry_offsets(&app, Some(width), false);
    assert_eq!(rows_fingerprint(&first.0), rows_fingerprint(&second.0));
    assert_eq!(first.1, second.1);
}

#[test]
fn main_render_cached_matches_uncached_byte_for_byte() {
    // The painted rows + entry offsets from the cached path must equal the raw
    // builder's output for the same state — across several widths and the
    // startup-card toggle. This is the load-bearing correctness proof.
    //
    // The fixtures together drive every segmentation edge branch that a plain
    // four-message transcript skips: `main_render_app_rich` carries a
    // render-time coalesced tool run (suppressed members) + a suppressed
    // reasoning pair + a live pending-assistant tail, and
    // `main_render_app_subagent` carries the conversation-title head-chrome
    // path. Each app mints a private `render_cache_session`, so sweeping all
    // three in one test cannot cross-pollute the process-wide LRU.
    let _theme = lock_main_render_theme();
    let fixtures: [(&str, TuiApp); 3] = [
        ("plain", main_render_app()),
        ("rich", main_render_app_rich()),
        ("subagent", main_render_app_subagent()),
    ];
    for (label, app) in &fixtures {
        for &width in &[20u16, 40, 60, 80, 120] {
            for &card in &[false, true] {
                let cached = transcript_lines_and_entry_offsets(app, Some(width), card);
                let uncached = transcript_lines_and_entry_offsets_uncached(app, Some(width), card);
                assert_eq!(
                    rows_fingerprint(&cached.0),
                    rows_fingerprint(&uncached.0),
                    "[{label}] cached rows must match uncached at width {width}, card {card}"
                );
                assert_eq!(
                    cached.1, uncached.1,
                    "[{label}] cached entry offsets must match uncached at width {width}, card {card}"
                );
            }
        }
    }
}

#[test]
fn main_render_rich_fixture_exercises_segmentation_edges() {
    // Pin that the rich fixture actually drives the suppressed-segment branches
    // the byte-for-byte sweep is meant to cover, so a future fixture edit that
    // silently stopped coalescing/suppressing wouldn't quietly narrow coverage.
    let app = main_render_app_rich();
    let entries = active_transcript_entries(&app);
    // Two adjacent reasoning entries -> a lead + one suppressed member.
    let reasoning_runs: Vec<_> = (0..entries.len())
        .filter_map(|i| reasoning_run_info(entries, i))
        .collect();
    assert!(
        reasoning_runs.contains(&ReasoningRun::Suppressed),
        "rich fixture must contain a suppressed reasoning member: {reasoning_runs:?}"
    );
    // Three adjacent same-tool same-status results -> a coalesced run with
    // suppressed members.
    let tool_runs: Vec<_> = (0..entries.len())
        .filter_map(|i| tool_run_info(entries, i, app.coalesce_tool_runs))
        .collect();
    assert!(
        tool_runs
            .iter()
            .any(|run| matches!(run, ToolRun::Lead { extras } if *extras >= 1)),
        "rich fixture must contain a coalesced tool-run lead: {tool_runs:?}"
    );
    assert!(
        tool_runs.contains(&ToolRun::Suppressed),
        "rich fixture must contain a suppressed tool-run member: {tool_runs:?}"
    );
    // A live pending-assistant tail is shown.
    assert!(
        pending_assistant_display_content(&app).is_some(),
        "rich fixture must show a pending-assistant tail"
    );
    // No settle-fold remains, so the cache is actually exercised (not bypassed).
    assert!(
        entries.iter().all(|entry| entry.settle.is_none()),
        "rich fixture must clear settles so the cache path is taken"
    );
}

/// The fg color of the first crescent-moon ("☽") span in `rows`, used to pin
/// the animated pending-tail tint.
fn first_moon_color(rows: &[Line<'static>]) -> Option<Color> {
    rows.iter()
        .flat_map(|line| line.spans.iter())
        .find(|span| span.content.as_ref() == "☽")
        .map(|span| span.style.fg)
        .unwrap_or(None)
}

#[test]
fn main_render_cache_pending_tail_moon_pulses_across_tick() {
    // Regression for the MainRenderKey-omits-animation-tick freeze: while a
    // turn is Running and a pending-assistant tail is shown, the tail's moon is
    // tinted by `TurnVisualState::Running.color(tick)`, which alternates
    // between two tints every 4 ticks (the `tick % 8 < 4` branch).
    // `main_render_key` folds that color bucket (gated on the
    // has-animating-tail predicate) so a cache hit on stable pending text can't
    // freeze the pulse. Advance the tick across the bucket boundary and assert
    // the cached moon color actually changes.
    let _theme = lock_main_render_theme();
    let mut app = test_app(SessionMode::Build);
    app.push_transcript_item(TranscriptItem::user("go"));
    app.pending_assistant
        .push_delta("streaming a stable answer tail");
    app.turn_visual = TurnVisualState::Running;
    let width = 60u16;

    // tick 0 -> 0 % 8 == 0 (< 4) -> the "secondary" tint.
    app.animation_tick = 0;
    let phase_low = app.turn_visual.color(0);
    let rows_low = transcript_lines_and_entry_offsets(&app, Some(width), false).0;
    assert_eq!(
        first_moon_color(&rows_low),
        Some(phase_low),
        "pending-tail moon must paint the tick-0 Running tint"
    );

    // tick 4 -> 4 % 8 == 4 (>= 4) -> the "accent" tint. A different mod-8 phase,
    // so the gated key dimension changes and the cached row is rebuilt.
    app.animation_tick = 4;
    let phase_high = app.turn_visual.color(4);
    assert_ne!(
        phase_low, phase_high,
        "precondition: the Running tint differs across a mod-8 boundary"
    );
    let rows_high = transcript_lines_and_entry_offsets(&app, Some(width), false).0;
    assert_eq!(
        first_moon_color(&rows_high),
        Some(phase_high),
        "cache must not freeze the pending-tail moon across a tick boundary"
    );

    // A within-bucket advance (4 -> 5, both in `% 8 >= 4`) keeps the SAME tint
    // and stays a cache hit: the gate folds only the two-state color bucket, so
    // within-bucket frames are not forced to miss.
    app.animation_tick = 5;
    let key_phase_5 = main_render_key(&app, width, false);
    assert!(
        main_render_cache::contains_main_key(&key_phase_5),
        "tick 5 shares tick 4's color bucket, so its key is already cached"
    );
}

#[test]
fn main_render_key_idle_tail_phase_is_stable_across_ticks() {
    // The has-animating-tail gate: when NO pending tail is showing (or the turn
    // is not Running), the folded phase is held at a constant 0 so a bare tick
    // advance never invalidates the idle key.
    let _theme = lock_main_render_theme();
    let mut app = main_render_app(); // settled transcript, no pending tail
    let width = 60u16;
    app.animation_tick = 0;
    let key_a = main_render_key(&app, width, false);
    app.animation_tick = 4; // crosses the Running color-bucket boundary
    let key_b = main_render_key(&app, width, false);
    assert_eq!(
        key_a, key_b,
        "an idle transcript with no animating tail must key identically across ticks"
    );
}

#[test]
fn main_render_cache_invalidates_on_revision_bump() {
    let _theme = lock_main_render_theme();
    let mut app = main_render_app();
    let width = 50u16;
    let before = transcript_lines_and_entry_offsets(&app, Some(width), false);
    // Mutate an entry's content and bump its revision (what streaming/collapse do).
    if let Some(entry) = app.transcript.first_mut() {
        if let TranscriptEntryKind::Message(item) = &mut entry.kind {
            item.content = "completely different first prompt text now".to_string();
        }
        entry.bump_revision();
    }
    let new_key = main_render_key(&app, width, false);
    assert!(
        !main_render_cache::contains_main_key(&new_key),
        "a revision bump produces a new, uncached key"
    );
    let after = transcript_lines_and_entry_offsets(&app, Some(width), false);
    assert_ne!(
        rows_fingerprint(&before.0),
        rows_fingerprint(&after.0),
        "the changed entry must produce different rows"
    );
    // And the cached path still matches the raw builder for the new state.
    let uncached = transcript_lines_and_entry_offsets_uncached(&app, Some(width), false);
    assert_eq!(rows_fingerprint(&after.0), rows_fingerprint(&uncached.0));
}

#[test]
fn main_render_cache_invalidates_on_width_change() {
    let _theme = lock_main_render_theme();
    let app = main_render_app();
    let _ = transcript_lines_and_entry_offsets(&app, Some(60), false);
    let key61 = main_render_key(&app, 61, false);
    assert!(
        !main_render_cache::contains_main_key(&key61),
        "a different width is a different, uncached key"
    );
    let _ = transcript_lines_and_entry_offsets(&app, Some(61), false);
    assert!(
        main_render_cache::contains_main_key(&key61),
        "the new width's key is now cached"
    );
}

#[test]
fn main_render_cache_invalidates_on_detail_toggle() {
    let _theme = lock_main_render_theme();
    let mut app = main_render_app();
    let width = 60u16;
    let _ = transcript_lines_and_entry_offsets(&app, Some(width), false);
    // Toggle a detail-policy dimension (verbosity) — part of the key.
    app.tool_output_verbosity = ToolOutputVerbosity::Verbose;
    let verbose_key = main_render_key(&app, width, false);
    assert!(
        !main_render_cache::contains_main_key(&verbose_key),
        "a verbosity change is a new, uncached key"
    );
    let _ = transcript_lines_and_entry_offsets(&app, Some(width), false);
    assert!(main_render_cache::contains_main_key(&verbose_key));

    // `show_reasoning_usage` is another detail dimension.
    app.show_reasoning_usage = !app.show_reasoning_usage;
    let reasoning_key = main_render_key(&app, width, false);
    assert!(
        !main_render_cache::contains_main_key(&reasoning_key),
        "toggling show_reasoning_usage is a new, uncached key"
    );
    let _ = transcript_lines_and_entry_offsets(&app, Some(width), false);
    assert!(main_render_cache::contains_main_key(&reasoning_key));
}

#[test]
fn main_render_cache_invalidates_on_theme_change() {
    let _theme = lock_main_render_theme();
    let app = main_render_app();
    let width = 60u16;
    let _ = transcript_lines_and_entry_offsets(&app, Some(width), false);
    // A `/theme` switch bumps the palette generation.
    crate::render::theme::bump_theme_generation();
    // The key rebuilt after the bump reflects the new palette generation and is
    // not yet cached.
    let themed_key = main_render_key(&app, width, false);
    assert!(
        !main_render_cache::contains_main_key(&themed_key),
        "a theme change is a new, uncached key"
    );
    let _ = transcript_lines_and_entry_offsets(&app, Some(width), false);
    assert!(main_render_cache::contains_main_key(&themed_key));
}

#[test]
fn main_render_cache_invalidates_on_card_selection_change() {
    let _theme = lock_main_render_theme();
    let mut app = main_render_app();
    let width = 60u16;
    let _ = transcript_lines_and_entry_offsets(&app, Some(width), false);
    // The card-selected entry restyles that entry's header → part of the key.
    app.selected_entry = Some(1);
    let selected_key = main_render_key(&app, width, false);
    assert!(
        !main_render_cache::contains_main_key(&selected_key),
        "changing the card-selected entry is a new, uncached key"
    );
    let _ = transcript_lines_and_entry_offsets(&app, Some(width), false);
    assert!(main_render_cache::contains_main_key(&selected_key));
}

#[test]
fn main_render_text_selection_changes_paint_but_keeps_rows_cached() {
    // A *text* selection (drag highlight) is layered onto a clone of the cached
    // rows as a post-pass — deliberately NOT part of the cache key. So the
    // underlying assembled rows stay a cache HIT, while the painted output still
    // changes. This is the design's correctness property: highlight is a cheap
    // per-frame restyle on already-built rows.
    let _theme = lock_main_render_theme();
    let mut app = main_render_app();
    let width = 60u16;
    let height = 20u16;
    // `render_transcript` paints into a text area that reserves a 1-cell
    // scrollbar gutter, so the cache key it builds uses `width - 1`. Capture the
    // key ONCE up front and reuse it for every presence check: re-deriving it
    // later would race on the process-wide theme generation that a concurrent
    // test may bump. Arming a text selection cannot change the key anyway —
    // `main_render_key` never reads `app.selection` — so the captured value is
    // the one every frame in this test looks up.
    let text_width = width.saturating_sub(1);
    let key = main_render_key(&app, text_width, false);
    let baseline = render_transcript_to_buffer(&app, width, height);
    assert!(
        main_render_cache::contains_main_key(&key),
        "the baseline frame warmed the cache"
    );

    // Arm a main-surface selection spanning some visible rows.
    app.selection = Some(selection::Selection::at(
        selection::SelectionSurface::Main,
        selection::Pos::new(0, 0),
        selection::SelectionMode::Cell,
        text_width,
    ));
    if let Some(sel) = app.selection.as_mut() {
        sel.cursor = selection::Pos::new(3, 10);
    }

    // The selection frame reuses the cached rows (the key is unchanged), then
    // restyles a clone as a post-pass.
    let selected = render_transcript_to_buffer(&app, width, height);
    assert!(
        main_render_cache::contains_main_key(&key),
        "the selection frame reused the cached rows (key unchanged)"
    );

    // The painted output differs: the selection highlight reverses the selected
    // cells (`Modifier::REVERSED`), so compare full cell appearance — symbol +
    // fg + bg + modifier — not just background.
    let cell_appearance = |buf: &ratatui::buffer::Buffer| -> Vec<(String, Color, Color, Modifier)> {
        (0..buf.area.height)
            .flat_map(|y| (0..buf.area.width).map(move |x| (x, y)))
            .map(|(x, y)| {
                let cell = &buf[(x, y)];
                (cell.symbol().to_string(), cell.fg, cell.bg, cell.modifier)
            })
            .collect()
    };
    assert_ne!(
        cell_appearance(&baseline),
        cell_appearance(&selected),
        "the selection highlight must change the painted output"
    );
}

// ---- Jump marks (§11.2 / 11G.2) -------------------------------------

/// Seed a transcript with enough turns that the view can scroll, and unpin it
/// to the top so a mark records a non-tail position.
fn jump_marks_app() -> TuiApp {
    let mut app = test_app(SessionMode::Build);
    // Deterministic 80x24 viewport so the jump-nav geometry these tests exercise
    // off-frame doesn't depend on the host terminal size (see `wide_block_app`).
    app.set_test_frame_size(80, 24);
    for index in 0..60 {
        app.push_transcript_item(TranscriptItem::user(format!("turn {index}")));
    }
    app
}

#[tokio::test]
async fn jump_mark_set_then_jump_back_drives_through_real_render() {
    // Keyboard path through the full keymap: `Alt+m` sets a mark, `Alt+'` pops
    // it. The marks are kept by stable entry id, so the count is what we assert
    // rather than the (terminal-size-dependent) exact scroll offset.
    let mut agent = test_agent(SessionMode::Build);
    let mut app = jump_marks_app();
    // Scroll up so the marked position is meaningfully above the tail.
    app.transcript_scroll = scroll::ScrollState::scrolled_up(20);

    handle_key(
        &mut app,
        &mut agent,
        KeyEvent::new(KeyCode::Char('m'), KeyModifiers::ALT),
    )
    .await
    .expect("alt-m sets a jump mark");
    assert_eq!(app.jump_marks.mark_count(), 1, "Alt+m must set one mark");
    assert!(
        app.status.contains("mark set"),
        "status must confirm the mark: {}",
        app.status
    );

    // The feature must survive the real fullscreen renderer.
    let _ = render_to_string(&app, 80, 24);

    // Move away (re-pin to the tail) then jump back.
    app.transcript_scroll = scroll::ScrollState::pinned();
    handle_key(
        &mut app,
        &mut agent,
        KeyEvent::new(KeyCode::Char('\''), KeyModifiers::ALT),
    )
    .await
    .expect("alt-' jumps back to the mark");
    assert_eq!(
        app.jump_marks.mark_count(),
        0,
        "jumping back must pop the mark off the stack",
    );
    assert!(
        app.status.contains("jumped back") || app.status.contains("no longer"),
        "status must report the jump-back outcome: {}",
        app.status
    );

    // And still renders cleanly after the jump.
    let painted = render_to_string(&app, 80, 24);
    assert!(!painted.is_empty());
}

#[test]
fn jump_mark_records_stable_entry_id_at_top_of_viewport() {
    let mut app = jump_marks_app();
    app.transcript_scroll = scroll::ScrollState::scrolled_up(30);

    // The id the renderer would mark is the top-visible entry's stable id.
    let expected = current_top_entry_id(&app).expect("a top entry exists");
    set_jump_mark(&mut app);
    assert_eq!(app.jump_marks.mark_count(), 1);

    // Re-pin to the tail, then jump back: the view must move off the tail
    // toward the marked entry, and the mark drains.
    app.transcript_scroll = scroll::ScrollState::pinned();
    assert!(app.transcript_scroll.is_following());
    jump_to_jump_mark(&mut app);
    assert_eq!(app.jump_marks.mark_count(), 0);
    // The marked entry id is still live, so the jump landed on it (status, not
    // a "no longer in transcript" failure).
    assert!(
        app.status.contains("jumped back"),
        "jump must land on the still-live marked entry #{expected}: {}",
        app.status
    );
}

#[test]
fn jump_mark_on_empty_transcript_is_a_safe_noop() {
    // Edge case: nothing to mark. Must not panic, must not record a mark, and
    // must surface a clear status — through the real renderer.
    let mut app = test_app(SessionMode::Build);
    assert!(app.transcript.is_empty());

    set_jump_mark(&mut app);
    assert_eq!(app.jump_marks.mark_count(), 0);
    assert!(
        app.status.contains("no transcript to mark"),
        "{}",
        app.status
    );

    // Jump-back with no marks set surfaces the "none set" hint, not a panic.
    jump_to_jump_mark(&mut app);
    assert!(app.status.contains("no jump marks"), "{}", app.status);

    let _ = render_to_string(&app, 80, 24);
}

#[test]
fn jump_back_history_summary_shown_when_stack_drained() {
    // After a jump, the mark stack is empty; a second `Alt+'` with no marks
    // surfaces the recent-jump history rather than the bare "none set" hint.
    let mut app = jump_marks_app();
    app.transcript_scroll = scroll::ScrollState::scrolled_up(25);
    set_jump_mark(&mut app);
    app.transcript_scroll = scroll::ScrollState::pinned();
    jump_to_jump_mark(&mut app); // lands + records history, drains the stack
    assert_eq!(app.jump_marks.mark_count(), 0);

    jump_to_jump_mark(&mut app); // no marks left
    assert!(
        app.status.contains("recent jumps") || app.status.contains("no jump marks"),
        "drained stack must show the recent-jump trail or the none hint: {}",
        app.status
    );
}

#[test]
fn jump_marks_survive_resize_and_repaint() {
    // Resize is where the feature paints: a mark set at one width must still be
    // jumpable after the viewport reflows to another width, because marks are
    // keyed by stable entry id (not a width-dependent row).
    let mut app = jump_marks_app();
    app.transcript_scroll = scroll::ScrollState::scrolled_up(20);
    set_jump_mark(&mut app);
    assert_eq!(app.jump_marks.mark_count(), 1);

    // Paint narrow, then wide — both must render without panicking.
    let narrow = render_to_string(&app, 40, 20);
    let wide = render_to_string(&app, 160, 50);
    assert!(!narrow.is_empty());
    assert!(!wide.is_empty());

    // Re-clamp scroll to a fresh geometry (as a real resize does), then jump
    // back: the mark is still resolvable.
    reanchor_active_scroll_on_resize(&mut app, None);
    app.transcript_scroll = scroll::ScrollState::pinned();
    jump_to_jump_mark(&mut app);
    assert_eq!(app.jump_marks.mark_count(), 0);
    assert!(
        app.status.contains("jumped back"),
        "mark must survive the reflow and resolve: {}",
        app.status
    );
}

#[test]
fn jump_marks_cleared_on_transcript_clear() {
    // `/clear` resets entry ids to 0, so stale marks would point at unrelated
    // new entries. They must be dropped. We exercise the same reset the clear
    // path performs.
    let mut app = jump_marks_app();
    set_jump_mark(&mut app);
    assert_eq!(app.jump_marks.mark_count(), 1);

    // Mirror the transcript-reset bookkeeping (`DispatchCommand::Clear`).
    app.transcript.clear();
    app.selected_entry = None;
    app.next_entry_id = 0;
    app.jump_marks = jump_marks::JumpMarkStack::new();

    assert_eq!(
        app.jump_marks.mark_count(),
        0,
        "marks must not survive a transcript rebuild",
    );
}

// ---- Minimap turn rail (§11.2 / 11G.3) ------------------------------

/// Seed a transcript with mixed user turns, tool calls, and a failure so the
/// rail has every marker kind to place, scrolled up so the viewport band is not
/// pinned to the tail.
fn minimap_app() -> TuiApp {
    let mut app = test_app(SessionMode::Build);
    for index in 0..20 {
        app.push_transcript_item(TranscriptItem::user(format!("ask {index}")));
        app.push_transcript_item(TranscriptItem::assistant(format!("answer {index}")));
        app.push_tool_result(sample_tool_result("grep", &format!("hit {index}")));
    }
    let mut failed = sample_tool_result("shell", "boom");
    failed.status = ToolStatus::Error;
    app.push_tool_result(failed);
    app
}

/// Render `app` through the real fullscreen `render()` into a `TestBackend`,
/// populating the frame-local hit registry, and return the terminal so the test
/// can both read the painted buffer and hit-test the registered targets.
fn render_into_terminal(app: &TuiApp, width: u16, height: u16) -> Terminal<TestBackend> {
    let backend = TestBackend::new(width, height);
    let mut terminal = Terminal::new(backend).expect("terminal");
    terminal.draw(|frame| render(frame, app)).expect("draw");
    terminal
}

/// Scan the painted buffer (and the live hit registry) for the first cell that
/// is a registered `MinimapJump` target, returning its `(column, row)`.
fn find_minimap_cell(app: &TuiApp, width: u16, height: u16) -> Option<(u16, u16)> {
    for row in 0..height {
        for col in 0..width {
            if let Some((_key, interaction::Action::MinimapJump(_))) = app.click_target_at(col, row)
            {
                return Some((col, row));
            }
        }
    }
    None
}

#[test]
fn minimap_off_by_default_registers_no_rail_targets() {
    let app = minimap_app();
    let _ = render_into_terminal(&app, 80, 24);
    assert!(
        !app.show_minimap,
        "the minimap rail is off until the user toggles it"
    );
    assert!(
        find_minimap_cell(&app, 80, 24).is_none(),
        "no rail cells register while the rail is off"
    );
}

#[tokio::test]
async fn alt_r_toggles_minimap_through_the_keymap() {
    let mut agent = test_agent(SessionMode::Build);
    let mut app = minimap_app();
    assert!(!app.show_minimap);

    handle_key(
        &mut app,
        &mut agent,
        KeyEvent::new(KeyCode::Char('r'), KeyModifiers::ALT),
    )
    .await
    .expect("alt-r toggles the minimap on");
    assert!(app.show_minimap, "Alt+r must turn the rail on");
    assert!(app.status.contains("minimap rail on"), "{}", app.status);

    // It survives the real renderer and now registers at least one rail cell.
    let _ = render_into_terminal(&app, 80, 24);
    assert!(
        find_minimap_cell(&app, 80, 24).is_some(),
        "an enabled rail registers clickable cells through render()"
    );

    handle_key(
        &mut app,
        &mut agent,
        KeyEvent::new(KeyCode::Char('r'), KeyModifiers::ALT),
    )
    .await
    .expect("alt-r toggles the minimap off");
    assert!(!app.show_minimap, "Alt+r must turn the rail off again");
    assert!(app.status.contains("minimap rail off"), "{}", app.status);
}

#[test]
fn minimap_rail_paints_markers_in_its_reserved_column() {
    let mut app = minimap_app();
    app.show_minimap = true;
    app.transcript_scroll = scroll::ScrollState::scrolled_up(10);

    let output = render_into_terminal(&app, 80, 24);
    let buffer = output.backend().buffer();
    // Walk the rightmost column (the rail's reserved column) and confirm at
    // least one marker glyph painted there.
    let rail_col = 80 - 1;
    let marker_glyphs = ["●", "◦", "▲", "·", "│"];
    let mut painted_marker = false;
    for y in 0..24 {
        let sym = buffer[(rail_col, y)].symbol();
        if marker_glyphs.contains(&sym) {
            painted_marker = true;
        }
    }
    assert!(
        painted_marker,
        "the rail column must paint at least one rail/marker glyph"
    );
}

#[test]
fn clicking_a_rail_cell_jumps_the_transcript() {
    let mut app = minimap_app();
    app.show_minimap = true;
    // Pin to the tail so a jump that lands above the tail is observable.
    app.transcript_scroll = scroll::ScrollState::pinned();

    // Render to register the rail cells, then click the first one.
    let _ = render_into_terminal(&app, 80, 30);
    let (col, row) =
        find_minimap_cell(&app, 80, 30).expect("an enabled rail registers a clickable cell");

    let before = app.transcript_scroll;
    let consumed = handle_mouse(
        &mut app,
        crossterm::event::MouseEvent {
            kind: MouseEventKind::Down(crossterm::event::MouseButton::Left),
            column: col,
            row,
            modifiers: KeyModifiers::NONE,
        },
    );
    assert!(consumed, "a click on a rail cell is consumed as a jump");
    // The very first (topmost) rail cell maps to an early entry, so jumping to
    // it moves the view off the pinned tail.
    assert_ne!(
        app.transcript_scroll, before,
        "clicking the top rail cell must move the viewport"
    );
    // And the app stays renderable afterwards.
    let painted = render_to_string(&app, 80, 30);
    assert!(!painted.is_empty());
}

#[test]
fn minimap_rail_survives_resize_and_empty_transcript() {
    // Empty transcript: the rail must paint nothing and register no targets,
    // never panic, across a couple of sizes.
    let mut app = test_app(SessionMode::Build);
    app.show_minimap = true;
    let _ = render_into_terminal(&app, 40, 12);
    assert!(find_minimap_cell(&app, 40, 12).is_none());
    let _ = render_into_terminal(&app, 120, 40);
    assert!(find_minimap_cell(&app, 120, 40).is_none());

    // Now with content, paint narrow then wide — both must render and register
    // rail cells without panicking (the rail is keyed by stable entry id, so a
    // reflow re-registers the same targets at fresh cells).
    let mut app = minimap_app();
    app.show_minimap = true;
    let narrow = render_to_string(&app, 24, 16);
    assert!(!narrow.is_empty());
    let _ = render_into_terminal(&app, 24, 16);
    let narrow_cell = find_minimap_cell(&app, 24, 16);
    let wide = render_to_string(&app, 160, 50);
    assert!(!wide.is_empty());
    let _ = render_into_terminal(&app, 160, 50);
    let wide_cell = find_minimap_cell(&app, 160, 50);
    assert!(
        narrow_cell.is_some() && wide_cell.is_some(),
        "the rail registers cells at both widths"
    );
}

#[test]
fn minimap_too_narrow_to_host_a_rail_falls_back_gracefully() {
    // A 2-column area cannot host both a rail and the scrollbar gutter, so the
    // rail is dropped and the body keeps the area. Must not panic.
    let (body, rail) = transcript_main_body_and_rail_areas(
        Rect {
            x: 0,
            y: 0,
            width: 2,
            height: 10,
        },
        true,
    );
    assert!(rail.is_none(), "no room for a rail at width 2");
    assert_eq!(body.width, 2, "the body keeps the whole area");

    // Wide enough: the rail carves the rightmost column off the body.
    let (body, rail) = transcript_main_body_and_rail_areas(
        Rect {
            x: 0,
            y: 0,
            width: 10,
            height: 10,
        },
        true,
    );
    let rail = rail.expect("a rail column at width 10");
    assert_eq!(rail.width, 1);
    assert_eq!(rail.x, 9, "rail sits on the right edge");
    assert_eq!(body.width, 9, "body wraps one column narrower");
}

// ---------------------------------------------------------------------------
// Horizontal navigation for wide blocks (§11.2 / 11G.4)
// ---------------------------------------------------------------------------

/// An app whose transcript holds one very wide, unbreakable line plus some
/// filler turns. The wide token has no spaces, so it cannot wrap-break on word
/// boundaries — it is exactly the wide-block case the feature targets.
fn wide_block_app() -> TuiApp {
    let mut app = test_app(SessionMode::Build);
    // Seed a deterministic small viewport so the off-frame transcript geometry
    // (`active_transcript_geometry` & friends) measures against a fixed 80x24
    // instead of the host terminal. On a tall console (e.g. the Windows CI
    // runner) the real height would make the short transcript fit with no
    // scrollback, so `ScrollUp` would be a no-op and the vertical-scroll
    // assertions below would spuriously fail. Pinning the size here removes that
    // platform dependence; the render-based assertions paint at 80x24 to match.
    app.set_test_frame_size(80, 24);
    // A few filler turns first, then the wide line LAST so it sits at the
    // tail-pinned bottom of the viewport and is reliably painted in the
    // render-based assertions below.
    for index in 0..6 {
        app.push_transcript_item(TranscriptItem::user(format!("filler {index}")));
    }
    // 240 columns of distinct, position-revealing content with no break
    // opportunity. `abc…xyzabc…` repeated lets a render assertion tell a
    // left-edge paint from a panned one.
    let wide: String = (0..240)
        .map(|i| char::from(b'a' + (i % 26) as u8))
        .collect();
    app.push_transcript_item(TranscriptItem::assistant(wide));
    app
}

#[tokio::test]
async fn soft_wrap_toggle_through_keymap_flips_mode_and_status() {
    // Keyboard path: `Alt+w` toggles the whole main view between soft-wrap and
    // no-wrap horizontal scroll, driven through the real keymap dispatch.
    let mut agent = test_agent(SessionMode::Build);
    let mut app = wide_block_app();
    assert!(app.wide_block.soft_wrap(), "default is soft-wrap on");

    handle_key(
        &mut app,
        &mut agent,
        KeyEvent::new(KeyCode::Char('w'), KeyModifiers::ALT),
    )
    .await
    .expect("alt-w toggles soft-wrap");
    assert!(!app.wide_block.soft_wrap(), "Alt+w must turn soft-wrap off");
    assert!(
        app.status.contains("soft-wrap off"),
        "status must report the new mode: {}",
        app.status
    );

    // Survives the real fullscreen renderer in no-wrap mode.
    let _ = render_to_string(&app, 80, 24);

    handle_key(
        &mut app,
        &mut agent,
        KeyEvent::new(KeyCode::Char('w'), KeyModifiers::ALT),
    )
    .await
    .expect("alt-w toggles back");
    assert!(app.wide_block.soft_wrap(), "second Alt+w restores wrap");
    assert!(app.status.contains("soft-wrap on"), "{}", app.status);
}

#[tokio::test]
async fn horizontal_pan_keys_scroll_the_no_wrap_view_and_clamp() {
    // Keyboard pan path: with soft-wrap off, `Alt+l` pans right and `Alt+h` pans
    // left. Driven through the real keymap so the dispatch arms are exercised.
    let mut agent = test_agent(SessionMode::Build);
    let mut app = wide_block_app();
    // Turn soft-wrap off so panning has an axis.
    handle_key(
        &mut app,
        &mut agent,
        KeyEvent::new(KeyCode::Char('w'), KeyModifiers::ALT),
    )
    .await
    .unwrap();
    // Paint once so `main_text_width` is stamped for the pan clamp metrics.
    let flush_left = render_to_string(&app, 80, 24);

    // Pan right a few steps.
    for _ in 0..3 {
        handle_key(
            &mut app,
            &mut agent,
            KeyEvent::new(KeyCode::Char('l'), KeyModifiers::ALT),
        )
        .await
        .unwrap();
    }
    assert!(
        app.wide_block.horizontal_offset() > 0,
        "Alt+l must pan the no-wrap view right",
    );
    let panned = render_to_string(&app, 80, 24);
    assert_ne!(
        flush_left, panned,
        "panning right must change the painted wide line",
    );

    // Pan all the way back left; offset saturates at 0.
    for _ in 0..10 {
        handle_key(
            &mut app,
            &mut agent,
            KeyEvent::new(KeyCode::Char('h'), KeyModifiers::ALT),
        )
        .await
        .unwrap();
    }
    assert_eq!(
        app.wide_block.horizontal_offset(),
        0,
        "Alt+h must pan back to the flush-left edge and saturate",
    );
    assert_eq!(
        render_to_string(&app, 80, 24),
        flush_left,
        "back at the left edge the paint matches the flush-left frame",
    );
}

#[tokio::test]
async fn pan_keys_are_consumed_but_inert_while_wrapping() {
    // Edge case: panning while soft-wrap is ON has no axis. The chord must still
    // be consumed (so it never leaks to the composer) and must leave the offset
    // at 0, surfacing the "turn wrap off" hint.
    let mut agent = test_agent(SessionMode::Build);
    let mut app = wide_block_app();
    assert!(app.wide_block.soft_wrap());

    let consumed = handle_key(
        &mut app,
        &mut agent,
        KeyEvent::new(KeyCode::Char('l'), KeyModifiers::ALT),
    )
    .await
    .unwrap();
    // `handle_key` returns whether the app should EXIT; the keymap dispatch
    // consumes the key so nothing reached the composer.
    assert!(!consumed, "pan key must not exit the app");
    assert!(
        app.input.is_empty(),
        "pan key must not type into the composer"
    );
    assert_eq!(
        app.wide_block.horizontal_offset(),
        0,
        "panning while wrapping is inert",
    );
    assert!(
        app.status.contains("soft-wrap on"),
        "inert pan must hint to toggle wrap: {}",
        app.status
    );
}

#[test]
fn shift_wheel_pans_horizontally_only_in_no_wrap_mode() {
    // Mouse path: Shift+wheel pans the no-wrap view horizontally; in the wrapped
    // view the same event falls through to a normal vertical scroll.
    let mut app = wide_block_app();

    // While wrapping, Shift+ScrollUp must NOT touch the horizontal offset and
    // must scroll vertically like a normal wheel event.
    let before_scroll = app.transcript_scroll.from_bottom();
    let _ = render_to_string(&app, 80, 24); // stamp geometry
    handle_mouse(
        &mut app,
        crossterm::event::MouseEvent {
            kind: MouseEventKind::ScrollUp,
            column: 0,
            row: 0,
            modifiers: KeyModifiers::SHIFT,
        },
    );
    assert_eq!(
        app.wide_block.horizontal_offset(),
        0,
        "Shift+wheel must not pan while wrapping",
    );
    assert_ne!(
        app.transcript_scroll.from_bottom(),
        before_scroll,
        "Shift+wheel while wrapping scrolls vertically",
    );

    // Now turn wrap off and re-pin to the tail; Shift+ScrollDown pans right.
    app.wide_block.toggle_wrap();
    app.transcript_scroll = scroll::ScrollState::pinned();
    let _ = render_to_string(&app, 80, 24); // stamp the no-wrap metrics
    let vscroll_before = app.transcript_scroll.from_bottom();
    handle_mouse(
        &mut app,
        crossterm::event::MouseEvent {
            kind: MouseEventKind::ScrollDown,
            column: 0,
            row: 0,
            modifiers: KeyModifiers::SHIFT,
        },
    );
    assert!(
        app.wide_block.horizontal_offset() > 0,
        "Shift+ScrollDown must pan the no-wrap view right",
    );
    assert_eq!(
        app.transcript_scroll.from_bottom(),
        vscroll_before,
        "horizontal pan must not move the vertical scroll",
    );
}

#[test]
fn no_wrap_view_renders_without_panic_at_narrow_and_wide_sizes() {
    // Resize coverage: the no-wrap paint must hold at a very narrow width (where
    // the wide line is mostly off-screen) and a wide one (where it fits), with no
    // panic and a stable clamp.
    let mut app = wide_block_app();
    app.wide_block.toggle_wrap();

    // Narrow: 20 columns. The painted offset clamps to the (large) content width.
    let narrow = render_to_string(&app, 20, 12);
    assert!(!narrow.is_empty());

    // Pan deep, then render very wide (300 cols) where the whole line fits: the
    // painted offset must clamp back to 0 (nothing to pan) without losing content.
    for _ in 0..40 {
        let _ = scroll_wide_block(&mut app, HorizontalDir::Right);
    }
    let wide = render_to_string(&app, 300, 12);
    assert!(!wide.is_empty());
    // The flush-left content (the wide line's first chars) is visible when the
    // viewport is wider than the line — output is panned, never hidden.
    assert!(
        wide.contains("abcdefghij"),
        "a viewport wider than the line shows its start: output is never hidden",
    );
}

#[test]
fn empty_transcript_soft_wrap_toggle_is_a_safe_noop_render() {
    // Edge case: toggling wrap and panning on an empty transcript must not panic
    // and must render cleanly through the real renderer.
    let mut app = test_app(SessionMode::Build);
    assert!(app.transcript.is_empty());
    // Paint once so the pan clamps against the real (narrow) startup-card width
    // rather than the pre-frame default of 0.
    let _ = render_to_string(&app, 80, 24);
    toggle_soft_wrap(&mut app);
    assert!(!app.wide_block.soft_wrap());
    // Panning never panics. The empty view's only content is the startup card,
    // which fits the 80-col viewport, so there is nothing to pan: the offset
    // stays at 0.
    let _ = scroll_wide_block(&mut app, HorizontalDir::Right);
    assert_eq!(
        app.wide_block.horizontal_offset(),
        0,
        "narrow chrome that fits the viewport leaves nothing to pan",
    );
    // A left-pan from the flush-left edge is a saturating no-op, never negative.
    let _ = scroll_wide_block(&mut app, HorizontalDir::Left);
    assert_eq!(app.wide_block.horizontal_offset(), 0);
    let painted = render_to_string(&app, 80, 24);
    assert!(!painted.is_empty());
}

