    assert_eq!(
        app.tool_actions.as_ref().unwrap().selected(),
        0,
        "cursor starts on the first item",
    );

    // The first item is the URL (it appears first in the output). Enter copies it.
    handle_key(
        &mut app,
        &mut agent,
        KeyEvent::new(KeyCode::Enter, KeyModifiers::NONE),
    )
